CrBA;AACAA;;AAEAA,aAAe/B,YAAS+B;AACxBA;IAPEA,CAAAA;;AAUAC,IAAAA,0BAAAA,sBAAAA;AAAAA,MAAAA;;;AAEFA,UAAYhC,YAASgC;AACrBA;AACAA;;AAEAA,aAAenC,WAAQmC,QAAUlC,QAAKkC;AACtCA;IAPEA,CAAAA;;AAUAC,IAAAA,yBAAAA,qBAAAA;AAAAA,MAAAA;;;AAEFA,UAAYjC,YAASiC;AACrBA;AACAA;;AAEAA,aAAepC,WAAQoC,WAAa1B,aAAU0B;AAC9CA;IAPEA,CAAAA;;AAUAC,IAAAA,qBAAAA,iBAAAA;AAAAA,MAAAA;;;MACEjC,eAAWJ;MACXG,eAAW;MACXkC,OAAApC,CAAAA,WAAWC,CAAXD;IAHFoC,CAAAA;;AAMAC,IAAAA,oBAAAA,aACE,SADFA,CAAAA;;AAIAC,IAAAA,qBAAAA,oCAAAA;AAAAA,MAAAA;;MACEA,OAAGnC,YAASmC;IADdA,CAAAA;;AAIAC,IAAAA,yBAAAA,qBAAAA;AAAAA,MAAAA;;MACEA,OAAA5C,IAAA0C,MAAAA,CAAAA,CAAIG,MAAAA,CAAAA;IADND,CAAAA;;AAIAE,IAAAA,yBAAAA,qBAAAA;AAAAA,MAAAA;;;MACErC,aAAS;MACTqC,OAAIV,MAAAA,CAAOhC,WAAOyB,QAAAA,CAAAA,CAAdO,CAAAA,EAAAA,MAAJpC,IAAIoC,QAAAA,EAAAA,EAAAA,CAAAA,EAAAA;IAFNU,CAAAA;;AAKAC,IAAAA,sBAAAA,kBAAAA;AAAAA,MAAAA;;;MACE1C,WAAYS;MACZA,gBAAY;MACZL,aAAY;MAEZsC,OAAA/C;IALF+C,CAAAA;IAQA,aAAM,MAAN,EAAW,oBAAX;IACA,aAAM,OAAN,EAAY,UAAZ;IAEA/C,IAAAgD,SAAAA,CAAAA;IAEAjD,OAAAc,sBAAAA,kBAAWD,OAAXC;AAAAA;;AAEFA;AACAA;AACAA;AACAA;IALEA,CAAAA;EA1SFd,GAAAA,WAAAA,EAAAA,IAAAA;AAAAD;"}}, {:offset=>{:line=>873, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["bcdice/common_command/lexer.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nrequire \"strscan\"\nrequire \"bcdice/normalize\"\n\nmodule BCDice\n  module CommonCommand\n    class Lexer\n      SYMBOLS = {\n        \"+\" => :PLUS,\n        \"-\" => :MINUS,\n        \"*\" => :ASTERISK,\n        \"/\" => :SLASH,\n        \"(\" => :PARENL,\n        \")\" => :PARENR,\n        \"[\" => :BRACKETL,\n        \"]\" => :BRACKETR,\n        \"?\" => :QUESTION,\n        \"@\" => :AT,\n      }.freeze\n\n      def initialize(source)\n        # sourceが空文字だとString#splitが空になる\n        source = source.split(\" \", 2).first || \"\"\n        @scanner = StringScanner.new(source)\n      end\n\n      def next_token\n        return [false, \"$\"] if @scanner.eos?\n\n        if (number = @scanner.scan(/\\d+/))\n          [:NUMBER, number.to_i]\n        elsif (cmp_op = @scanner.scan(/[<>!=]+/))\n          [:CMP_OP, Normalize.comparison_operator(cmp_op)]\n        else\n          char = @scanner.getch.upcase\n          type = SYMBOLS[char] || char.to_sym\n          [type, char]\n        end\n      end\n\n      def source\n        @scanner.string\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "self", "require", "<module:BCDice>", "<module:CommonCommand>", "<class:Lexer>", "freeze", "initialize", "source", "$ret_or_1", "split", "2", "first", "@scanner", "StringScanner", "new", "next_token", "eos?", "number", "scan", "to_i", "cmp_op", "Normalize", "comparison_operator", "char$", "getch", "upcase", "type", "SYMBOLS", "[]", "to_sym", "string"], :mappings=>"AAAAA,8CAAAA,gBAAAA;EAAAA;;;EAEAC,IAAAC,SAAAA,CAAQF,SAARE;EACAD,IAAAC,SAAAA,CAAQF,kBAARE;EAEAF,OAAAG;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;MACEA,OAAAC;MAAAA;;QAAAA;;AAAAA;;QACE,mCAAU,4DAAA,KACD,MADC,EAAA,KAED,OAFC,EAAA,KAGD,UAHC,EAAA,KAID,OAJC,EAAA,KAKD,QALC,EAAA,KAMD,QANC,EAAA,KAOD,UAPC,EAAA,KAQD,UARC,EAAA,KASD,UATC,EAAA,KAUD,IAVC,EAWTC,QAAAA,CAAAA,CAXD;;AAaAC,QAAAA,0BAAAA,sBAAeC,MAAfD;AAAAA,UAAAA;;;UAEEC,SAAS,CAAA,QAAAC,CAAAA,YAAAD,MAAME,OAAAA,CAAOH,GAAb,EAAkBI,CAAZD,CAAcE,OAAAA,CAAAA,CAApBH,CAAA,CAAA,GAAA,CAAA,SAAA,IAAA,CAA8BF,EAA9B,CAAA;UACTA,OAAAM,CAAAA,eAAWC,mBAAaC,KAAAA,CAAKP,MAALO,CAAxBF;QAHFN,CAAAA;;AAMAS,QAAAA,0BAAAA,sBAAAA;AAAAA,UAAAA;;;UACE,IAAA,QAAuBH,YAAQI,SAAAA,CAAAA,CAA/B,CAAA;YAAA,OAAO,CAAC,KAAD,EAAQD,GAAR;UAAP;UAEA,IAAA,QAAIE,CAAAA,SAASL,YAAQM,MAAAA,CAAM,KAANA,CAAjBD,CAAJ,CAAA;YACEF,OAAA,CAAC,QAAD,EAAUE,MAAME,MAAAA,CAAAA,CAAhB;UADF,OAEA,IAAA,QAAOC,CAAAA,SAASR,YAAQM,MAAAA,CAAM,SAANA,CAAjBE,CAAP,CAAA;YACEL,OAAA,CAAC,QAAD,EAAUM,eAASC,qBAAAA,CAAqBF,MAArBE,CAAnB;UADF;;YAGEC,QAAOX,YAAQY,OAAAA,CAAAA,CAAMC,QAAAA,CAAAA;YACrBC,OAAO,CAAA,QAAAlB,CAAAA,YAAAmB,aAAOC,OAAAA,CAACL,KAADK,CAAPpB,CAAA,CAAA,GAAA,CAAA,SAAA,IAAA,CAAiBe,KAAIM,QAAAA,CAAAA,CAArB,CAAA;YACPd,OAAA,CAACW,IAAD,EAAOH,KAAP;UALF;QALFR,CAAAA;QAcAX,OAAAG,sBAAAA,kBAAAA;AAAAA,UAAAA;;UACEA,OAAAK,YAAQkB,QAAAA,CAAAA;QADVvB,CAAAA;MAlCFH,GAAAA,WAAAA,EAAAA,IAAAA;IADFD,GAAAA,WAAAA;EADFD,GAAAA,WAAAA;AALAH;"}}, {:offset=>{:line=>934, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["./singleton.rb"], :sourcesContent=>["module Singleton\n  def clone\n    raise TypeError, \"can't clone instance of singleton \#{self.class}\"\n  end\n\n  def dup\n    raise TypeError, \"can't dup instance of singleton \#{self.class}\"\n  end\n\n  module SingletonClassMethods\n    def clone\n      Singleton.__init__(super)\n    end\n\n    def inherited(sub_klass)\n      super\n      Singleton.__init__(sub_klass)\n    end\n  end\n\n  class << Singleton\n    def __init__(klass)\n      klass.instance_eval do\n        @singleton__instance__ = nil\n      end\n      def klass.instance\n        return @singleton__instance__ if @singleton__instance__\n        @singleton__instance__ = new\n      end\n      klass\n    end\n\n    def included(klass)\n      super\n      klass.extend SingletonClassMethods\n      Singleton.__init__(klass)\n    end\n  end\nend\n"], :names=>["<top (required)>", "<module:Singleton>", "clone", "self", "raise", "TypeError", "class", "dup", "<module:SingletonClassMethods>", "Singleton", "__init__", "inherited", "sub_klass", "klass", "instance_eval", "block in __init__", "block (2 levels) in __init__", "@singleton__instance__", "instance", "new", "included", "extend", "SingletonClassMethods"], :mappings=>"AAAAA,4BAAAA,gBAAAA;EAAAA;;EAAAA,OAAAC;EAAAA;;IAAAA;;;;AACEC,IAAAA,qBAAAA,iBAAAA;AAAAA,MAAAA;;MACEA,OAAAC,IAAAC,OAAAA,CAAMC,eAAN,EAAkBH,oCAAD,GAAA,CAAqCC,IAAIG,OAAAA,CAAAA,CAAzC,CAAjBF;IADFF,CAAAA;;AAIAK,IAAAA,mBAAAA,eAAAA;AAAAA,MAAAA;;MACEA,OAAAJ,IAAAC,OAAAA,CAAMC,eAAN,EAAkBE,kCAAD,GAAA,CAAmCJ,IAAIG,OAAAA,CAAAA,CAAvC,CAAjBF;IADFG,CAAAA;IAIAC;IAAAA;;MAAAA;;;;AACEN,MAAAA,qBAAAA,iBAAAA;AAAAA,QAAAA;;QAAAA;QACEA,OAAAO,eAASC,UAAAA,CAAU,OAAAP,IAAA,EAAA,gDAAA,SAAA,EAAA,EAAA,EAAA,MAAA,CAAVO;MADXR,CAAAA;MAIAM,OAAAG,yBAAAA,qBAAcC,SAAdD;AAAAA,QAAAA;;QAAAA;;QACE,OAAAR,IAAA,EAAA,wDAAA,aAAA,EAAA,CAAAS,SAAA,CAAA,EAAA,MAAA;QACAD,OAAAF,eAASC,UAAAA,CAAUE,SAAVF;MAFXC,CAAAA;IALFH,GAAAA,WAAAA;IAWAP,OAAA;MAAA;;;;AACES,MAAAA,wBAAAA,oBAAaG,KAAbH;AAAAA,QAAAA;;;QACOI,MAALD,KAAKC,iBAAAA,EAAAA,EAAAA,EAALC,aAAAA,EAAAC;;UACEA,OAAAC,CAAAA,6BAAyB,GAAzBA,CADFF,CAAAA,GAAAA,SAAAA,CAAKD;QAGLI,MAAIL,KAAJK,eAAAA,oBAAAA;AAAAA,UAAAA;AAAAA;;;UACE,IAAA,QAAiCD,0BAAjC,CAAA;YAAA,OAAOA;UAAP;UACAC,OAAAD,CAAAA,6BAAyBd,IAAAgB,KAAAA,CAAAA,CAAzBF;QAFFC,CAAAA;QAIAR,OAAAG;MARFH,CAAAA;MAWA,OAAAU,wBAAAA,oBAAaP,KAAbO;AAAAA,QAAAA;;QAAAA;;QACE,OAAAjB,IAAA,EAAA,sDAAA,YAAA,EAAA,CAAAU,KAAA,CAAA,EAAA,MAAA;QACAA,KAAKQ,QAAAA,CAAQC,2BAARD;QACLD,OAAAX,eAASC,UAAAA,CAAUG,KAAVH;MAHXU,CAAAA;IAZF,4BAASX,eAAT;EApBFR,GAAAA,WAAAA;AAAAD;"}}, {:offset=>{:line=>1014, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["bcdice/common_command/add_dice/node.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nrequire \"singleton\"\n\nmodule BCDice\n  module CommonCommand\n    module AddDice\n      # 加算ロールの構文解析木のノードを格納するモジュール\n      module Node\n        # 加算ロールコマンドのノード。\n        #\n        # 目標値が設定されていない場合は +lhs+ のみを使用する。\n        # 目標値が設定されている場合は、+lhs+、+cmp_op+、+rhs+ を使用する。\n        class Command\n          # 左辺のノード\n          # @return [Object]\n          attr_reader :lhs\n          # 比較演算子\n          # @return [Symbol]\n          attr_reader :cmp_op\n          # 右辺のノード\n          # @return [Integer, String]\n          attr_reader :rhs\n\n          # ノードを初期化する\n          # @param [Object] lhs 左辺のノード\n          # @param [Symbol] cmp_op 比較演算子\n          # @param [Integer, String] rhs 右辺のノード\n          def initialize(secret, lhs, cmp_op = nil, rhs = nil)\n            @secret = secret\n            @lhs = lhs\n            @cmp_op = cmp_op\n            @rhs = rhs\n          end\n\n          # 文字列に変換する\n          # @param game_system [BCDice::Base]\n          # @return [String]\n          def expr(game_system)\n            @lhs.expr(game_system) + cmp_op_text + @rhs&.eval(game_system, nil).to_s\n          end\n\n          # ノードのS式を返す\n          # @return [String]\n          def s_exp\n            if @cmp_op\n              \"(Command (\#{@cmp_op} \#{@lhs.s_exp} \#{@rhs.s_exp}))\"\n            else\n              \"(Command \#{@lhs.s_exp})\"\n            end\n          end\n\n          def eval(game_system, randomizer)\n            randomizer = Randomizer.new(randomizer, game_system)\n            total = @lhs.eval(game_system, randomizer)\n\n            interrim_expr =\n              unless randomizer.rand_results.size <= 1 && @lhs.is_a?(Node::DiceRoll)\n                @lhs.output\n              end\n\n            result =\n              if @cmp_op\n                rhs = @rhs.eval(game_system, nil)\n                game_system.check_result(total, randomizer.rand_results, @cmp_op, rhs)\n              end\n            result ||= Result.new\n\n            sequence = [\n              \"(\#{expr(game_system)})\",\n              interrim_expr,\n              total,\n              result&.text\n            ].compact\n\n            result.tap do |r|\n              r.secret = @secret\n              r.text = sequence.join(\" ＞ \")\n            end\n          end\n\n          private\n\n          # メッセージ中で比較演算子をどのように表示するかを返す\n          # @return [String]\n          def cmp_op_text\n            case @cmp_op\n            when :'!='\n              \"<>\"\n            when :==\n              \"=\"\n            else\n              @cmp_op.to_s\n            end\n          end\n        end\n\n        class UndecidedTarget\n          include Singleton\n\n          def eval(_game_system, _randomizer)\n            \"?\"\n          end\n\n          def include_dice?\n            false\n          end\n\n          def expr(_game_system)\n            \"?\"\n          end\n\n          def output\n            \"?\"\n          end\n\n          alias s_exp output\n        end\n\n        # 二項演算子のノード\n        class BinaryOp\n          # ノードを初期化する\n          # @param [Object] lhs 左のオペランドのノード\n          # @param [Symbol] op 演算子\n          # @param [Object] rhs 右のオペランドのノード\n          def initialize(lhs, op, rhs)\n            @lhs = lhs\n            @op = op\n            @rhs = rhs\n          end\n\n          # ノードを評価する\n          #\n          # 左右のオペランドをそれぞれ再帰的に評価した後で、演算を行う。\n          #\n          # @param game_system [BCDice::Base]\n          # @param randomizer [Randomizer] ランダマイザ\n          # @return [Integer] 評価結果\n          def eval(game_system, randomizer)\n            lhs = @lhs.eval(game_system, randomizer)\n            rhs = @rhs.eval(game_system, randomizer)\n\n            return calc(lhs, rhs, game_system.round_type).to_i\n          end\n\n          # @return [Boolean]\n          def include_dice?\n            @lhs.include_dice? || @rhs.include_dice?\n          end\n\n          # 文字列に変換する\n          # @return [String]\n          def expr(game_system)\n            lhs = @lhs.expr(game_system)\n            rhs = @rhs.expr(game_system)\n\n            \"\#{lhs}\#{@op}\#{rhs}\"\n          end\n\n          # メッセージへの出力を返す\n          # @return [String]\n          def output\n            \"\#{@lhs.output}\#{@op}\#{@rhs.output}\"\n          end\n\n          # ノードのS式を返す\n          # @return [String]\n          def s_exp\n            \"(\#{op_for_s_exp} \#{@lhs.s_exp} \#{@rhs.s_exp})\"\n          end\n\n          private\n\n          # 演算を行う\n          # @param lhs [Integer] lhs 左のオペランド\n          # @param rhs [Integer] 右のオペランド\n          # @param _round_type [Symbol] ゲームシステムの端数処理設定\n          # @return [Integer] 演算の結果\n          def calc(lhs, rhs, _round_type)\n            lhs.send(@op, rhs).to_i\n          end\n\n          # S式で使う演算子の表現を返す\n          # @return [String]\n          def op_for_s_exp\n            @op\n          end\n        end\n\n        # 除算ノードの基底クラス\n        #\n        # 定数 +ROUNDING_METHOD+ で端数処理方法を示す記号\n        # ( +'U'+, +'R'+, +''+ ) を定義すること。\n        # また、除算および端数処理を行う +divide_and_round+ メソッドを実装すること。\n        class DivideBase < BinaryOp\n          # ノードを初期化する\n          # @param [Object] lhs 左のオペランドのノード\n          # @param [Object] rhs 右のオペランドのノード\n          def initialize(lhs, rhs)\n            super(lhs, :/, rhs)\n          end\n\n          # 文字列に変換する\n          #\n          # 通常の結果の末尾に、端数処理方法を示す記号を付加する。\n          #\n          # @return [String]\n          def expr(game_system)\n            \"\#{super(game_system)}\#{rounding_method}\"\n          end\n\n          # メッセージへの出力を返す\n          #\n          # 通常の結果の末尾に、端数処理方法を示す記号を付加する。\n          #\n          # @return [String]\n          def output\n            \"\#{super}\#{rounding_method}\"\n          end\n\n          private\n\n          # 端数処理方法を示す記号を返す\n          # @return [String]\n          def rounding_method\n            self.class::ROUNDING_METHOD\n          end\n\n          # S式で使う演算子の表現を返す\n          # @return [String]\n          def op_for_s_exp\n            \"\#{@op}\#{rounding_method}\"\n          end\n\n          # 演算を行う\n          # @param lhs [Integer] 左のオペランド\n          # @param rhs [Integer] 右のオペランド\n          # @param round_type [Symbol] ゲームシステムの端数処理設定\n          # @return [Integer] 演算の結果\n          def calc(lhs, rhs, round_type)\n            if rhs.zero?\n              return 1\n            end\n\n            return divide_and_round(lhs, rhs, round_type).to_i\n          end\n\n          # 除算および端数処理を行う\n          # @param dividend [Integer] 被除数\n          # @param divisor [Integer] 除数（0以外）\n          # @param round_type [Symbol] ゲームシステムの端数処理設定\n          # @return [Integer]\n          def divide_and_round(dividend, divisor, round_type)\n            raise NotImplementedError\n          end\n        end\n\n        # 除算（端数処理はゲームシステム依存）のノード\n        class DivideWithGameSystemDefault < DivideBase\n          ROUNDING_METHOD = \"\"\n\n          private\n\n          # 除算および端数処理を行う\n          # @param dividend [Integer] 被除数\n          # @param divisor [Integer] 除数（0以外）\n          # @param round_type [Symbol] ゲームシステムの端数処理設定\n          # @return [Integer]\n          def divide_and_round(dividend, divisor, round_type)\n            case round_type\n            when RoundType::CEIL\n              (dividend.to_f / divisor).ceil\n            when RoundType::ROUND\n              x = dividend.to_f / divisor\n              x.negative? ? -(x.abs.round) : x.round\n            else # RoundType::FLOOR\n              (dividend / divisor).floor\n            end\n          end\n        end\n\n        # 除算（切り上げ）のノード\n        class DivideWithRoundingUp < DivideBase\n          # 端数処理方法を示す記号\n          ROUNDING_METHOD = \"U\"\n\n          private\n\n          # 除算および端数処理を行う\n          # @param (see DivideWithGameSystemDefault#divide_and_round)\n          # @return [Integer]\n          def divide_and_round(dividend, divisor, _round_type)\n            (dividend.to_f / divisor).ceil\n          end\n        end\n\n        # 除算（四捨五入）のノード\n        class DivideWithRoundingOff < DivideBase\n          # 端数処理方法を示す記号\n          ROUNDING_METHOD = \"R\"\n\n          private\n\n          # 除算および端数処理を行う\n          # @param (see DivideWithGameSystemDefault#divide_and_round)\n          # @return [Integer]\n          def divide_and_round(dividend, divisor, _round_type)\n            x = dividend.to_f / divisor\n            x.negative? ? -(x.abs.round) : x.round\n          end\n        end\n\n        # 除算（切り捨て）のノード\n        class DivideWithRoundingDown < DivideBase\n          # 端数処理方法を示す記号\n          ROUNDING_METHOD = \"F\"\n\n          private\n\n          # 除算および端数処理を行う\n          # @param (see DivideWithGameSystemDefault#divide_and_round)\n          # @return [Integer]\n          def divide_and_round(dividend, divisor, _round_type)\n            (dividend / divisor).floor\n          end\n        end\n\n        # 符号反転のノード\n        class Negate\n          # 符号反転の対象\n          # @return [Object]\n          attr_reader :body\n\n          # ノードを初期化する\n          # @param [Object] body 符号反転の対象\n          def initialize(body)\n            @body = body\n          end\n\n          # ノードを評価する\n          #\n          # 対象オペランドを再帰的に評価した後、評価結果の符号を反転する。\n          #\n          # @param [Randomizer] randomizer ランダマイザ\n          # @return [Integer] 評価結果\n          def eval(game_system, randomizer)\n            -@body.eval(game_system, randomizer).to_i\n          end\n\n          # @return [Boolean]\n          def include_dice?\n            @body.include_dice?\n          end\n\n          # 文字列に変換する\n          # @return [String]\n          def expr(game_system)\n            \"-\#{@body.expr(game_system)}\"\n          end\n\n          # メッセージへの出力を返す\n          # @return [String]\n          def output\n            \"-\#{@body.output}\"\n          end\n\n          # ノードのS式を返す\n          # @return [String]\n          def s_exp\n            \"(- \#{@body.s_exp})\"\n          end\n        end\n\n        # ダイスロールのノード\n        class DiceRoll\n          # ノードを初期化する\n          # @param [Number] times ダイスを振る回数のノード\n          # @param [Number] sides ダイスの面数のノード\n          def initialize(times, sides)\n            @times = times\n            @sides = sides\n\n            # ダイスを振った結果の出力\n            @text = nil\n          end\n\n          # ノードを評価する（ダイスを振る）\n          #\n          # 評価結果は出目の合計値になる。\n          # 出目はランダマイザに記録される。\n          #\n          # @param [Randomizer] randomizer ランダマイザ\n          # @return [Integer] 評価結果（出目の合計値）\n          def eval(game_system, randomizer)\n            times = @times.eval(game_system, nil)\n            sides = eval_sides(game_system)\n\n            dice_list = randomizer.roll(times, sides)\n\n            total = dice_list.sum()\n            @text = \"\#{total}[\#{dice_list.join(',')}]\"\n\n            return total.to_i\n          end\n\n          # @return [Boolean]\n          def include_dice?\n            true\n          end\n\n          # 文字列に変換する\n          # @return [String]\n          def expr(game_system)\n            times = @times.eval(game_system, nil)\n            sides = eval_sides(game_system)\n\n            \"\#{times}D\#{sides}\"\n          end\n\n          # メッセージへの出力を返す\n          # @return [String]\n          def output\n            @text\n          end\n\n          # ノードのS式を返す\n          # @return [String]\n          def s_exp\n            \"(DiceRoll \#{@times.s_exp} \#{@sides.s_exp})\"\n          end\n\n          private\n\n          def eval_sides(game_system)\n            @sides.eval(game_system, nil)\n          end\n        end\n\n        class ImplicitSidesDiceRoll < DiceRoll\n          # @param [Number] times ダイスを振る回数のノード\n          def initialize(times)\n            @times = times\n            @text = nil\n          end\n\n          # @return [String]\n          def s_exp\n            \"(ImplicitSidesDiceRoll \#{@times.s_exp})\"\n          end\n\n          private\n\n          def eval_sides(game_system)\n            game_system.sides_implicit_d\n          end\n        end\n\n        # フィルタ処理付きダイスロールのノード。\n        #\n        # ダイスロール後、条件に従って出目を選択し、和を求める。\n        class DiceRollWithFilter\n          # フィルタの構造体\n          #\n          # 各フィルタには、あらかじめソートされた出目の配列が渡される。\n          #\n          # @!attribute abbr\n          #   @return [Symbol] フィルタの略称\n          # @!attribute apply\n          #   @return [Proc] フィルタ処理の内容\n          Filter = Struct.new(:abbr, :apply)\n\n          # 大きな出目から複数個取る\n          KEEP_HIGHEST = Filter.new(\n            :KH,\n            lambda { |sorted_values, n| sorted_values.reverse.take(n) }\n          ).freeze\n\n          # 小さな出目から複数個取る\n          KEEP_LOWEST = Filter.new(\n            :KL,\n            lambda { |sorted_values, n| sorted_values.take(n) }\n          ).freeze\n\n          # 大きな出目から複数個除く\n          DROP_HIGHEST = Filter.new(\n            :DH,\n            lambda { |sorted_values, n| sorted_values.reverse.drop(n) }\n          ).freeze\n\n          # 小さな出目から複数個除く\n          DROP_LOWEST = Filter.new(\n            :DL,\n            lambda { |sorted_values, n| sorted_values.drop(n) }\n          ).freeze\n\n          # ノードを初期化する\n          # @param [Object] times ダイスを振る回数のノード\n          # @param [Object, :implicit] sides ダイスの面数のノード（暗黙の面数を参照したい場合は `:implicit`）\n          # @param [Object] n_filtering ダイスを残す/減らす個数のノード\n          # @param [Filter] filter フィルタ\n          def initialize(times, sides, n_filtering, filter)\n            if sides != :implicit && !sides.respond_to?(:eval)\n              raise TypeError, \"sides must be a Node or :implicit (\#{sides.inspect})\"\n            end\n\n            @times = times\n            @sides = sides\n            @n_filtering = n_filtering\n            @filter = filter\n\n            # ダイスを振った結果の出力\n            @text = nil\n          end\n\n          # ノードを評価する（ダイスを振り、出目を選択して和を求める）\n          #\n          # 評価結果は出目の合計値になる。\n          # 出目はランダマイザに記録される。\n          #\n          # @param [Randomizer] randomizer ランダマイザ\n          # @return [Integer] 評価結果（出目の合計値）\n          def eval(game_system, randomizer)\n            times = @times.eval(game_system, nil)\n            sides = eval_sides(game_system)\n            n_filtering = @n_filtering.eval(game_system, nil)\n\n            sorted_values = randomizer.roll(times, sides).sort\n            total = @filter\n                    .apply[sorted_values, n_filtering]\n                    .sum()\n\n            @text = \"\#{total}[\#{sorted_values.join(',')}]\"\n\n            return total.to_i\n          end\n\n          # @return [Boolean]\n          def include_dice?\n            true\n          end\n\n          # 暗黙の面数を参照するか?\n          # @return [Boolean]\n          def implicit_sides?\n            @sides == :implicit\n          end\n\n          # 文字列に変換する\n          # @return [String]\n          def expr(game_system)\n            times = @times.eval(game_system, nil)\n            sides = eval_sides(game_system)\n            n_filtering = @n_filtering.eval(game_system, nil)\n\n            \"\#{times}D\#{sides}\#{@filter.abbr}\#{n_filtering}\"\n          end\n\n          # メッセージへの出力を返す\n          # @return [String]\n          def output\n            @text\n          end\n\n          # ノードのS式を返す\n          # @return [String]\n          def s_exp\n            sides_s_exp = implicit_sides? ? @sides.inspect : @sides.s_exp\n\n            \"(DiceRollWithFilter \#{@times.s_exp} \#{sides_s_exp} \#{@filter.abbr.inspect} \#{@n_filtering.s_exp})\"\n          end\n\n          private\n\n          # 面数を評価する\n          # @return [Integer] 指定された面数または暗黙の面数\n          def eval_sides(game_system)\n            if implicit_sides?\n              game_system.sides_implicit_d\n            else\n              @sides.eval(game_system, nil)\n            end\n          end\n        end\n\n        # カッコで式をまとめるノード\n        class Parenthesis\n          # @param expr [Object] カッコ内のノード\n          def initialize(expr)\n            @expr = expr\n          end\n\n          # @param randomizer [Randomizer]\n          # @return [integer]\n          def eval(game_system, randomizer)\n            @expr.eval(game_system, randomizer).to_i\n          end\n\n          # @return [Boolean]\n          def include_dice?\n            @expr.include_dice?\n          end\n\n          # @return [String]\n          def expr(game_system)\n            \"(\#{@expr.expr(game_system)})\"\n          end\n\n          # @return [String]\n          def output\n            \"(\#{@expr.output})\"\n          end\n\n          # @return [String] S式\n          def s_exp\n            \"(Parenthesis \#{@expr.s_exp})\"\n          end\n        end\n\n        # 数値のノード\n        class Number\n          # 値\n          # @return [Integer]\n          attr_reader :literal\n\n          # ノードを初期化する\n          # @param [Integer] literal 値\n          def initialize(literal)\n            @literal = literal.to_i\n          end\n\n          # 符号を反転した結果の数値ノードを返す\n          # @return [Number]\n          def negate\n            Number.new(-@literal)\n          end\n\n          # ノードを評価する\n          # @return [Integer] 格納している値\n          def eval(_game_system, _randomizer)\n            @literal.to_i\n          end\n\n          # @return [Boolean]\n          def include_dice?\n            false\n          end\n\n          # 文字列に変換する\n          # @return [String]\n          def expr(_game_system)\n            @literal.to_s\n          end\n\n          def output\n            @literal.to_s\n          end\n\n          alias s_exp output\n        end\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "self", "require", "<module:BCDice>", "<module:CommonCommand>", "<module:AddDice>", "<module:Node>", "<class:Command>", "attr_reader", "initialize", "secret", "lhs", "cmp_op", "rhs", "@secret", "@lhs", "@cmp_op", "@rhs", "expr", "game_system", "+", "cmp_op_text", "to_s", "s_exp", "eval", "randomizer", "Randomizer", "new", "total", "interrim_expr", "<=", "rand_results", "size", "1", "is_a?", "Node::DiceRoll", "Node", "output", "result", "check_result", "$ret_or_1", "Result", "sequence", "compact", "tap", "block in eval", "r", "block (2 levels) in eval", "secret=", "text=", "join", "private", "<class:UndecidedTarget>", "include", "Singleton", "include_dice?", "<class:BinaryOp>", "op", "@op", "calc", "round_type", "to_i", "op_for_s_exp", "_round_type", "send", "<class:DivideBase>", "rounding_method", "class::ROUNDING_METHOD", "class", "zero?", "divide_and_round", "dividend", "divisor", "raise", "NotImplementedError", "BinaryOp", "<class:DivideWithGameSystemDefault>", "RoundType::CEIL", "RoundType", "/", "to_f", "ceil", "RoundType::ROUND", "x", "negative?", "abs", "round", "-@", "floor", "DivideBase", "<class:DivideWithRoundingUp>", "<class:DivideWithRoundingOff>", "<class:DivideWithRoundingDown>", "<class:Negate>", "@body", "<class:DiceRoll>", "times", "sides", "@times", "@sides", "@text", "eval_sides", "dice_list", "roll", "sum", "<class:ImplicitSidesDiceRoll>", "sides_implicit_d", "DiceRoll", "<class:DiceRollWithFilter>", "Struct", "Filter", "lambda", "block in <class:DiceRollWithFilter>", "sorted_values", "n", "block (2 levels) in <class:DiceRollWithFilter>", "reverse", "take", "freeze", "drop", "n_filtering", "filter", "respond_to?", "TypeError", "inspect", "@n_filtering", "@filter", "sort", "apply", "[]", "implicit_sides?", "==", "abbr", "sides_s_exp", "<class:Parenthesis>", "@expr", "<class:Number>", "literal", "@literal", "negate", "Number", "_game_system", "_randomizer"], :mappings=>"AAAAA,sDAAAA,gBAAAA;EAAAA;;;EAEAC,IAAAC,SAAAA,CAAQF,WAARE;EAEAF,OAAAG;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;MACEA,OAAAC;MAAAA;;QAAAA;;QAEEA,OAAAC;QAAAA;;UAAAA;;;UAKEC;UAAAA;;YAAAA;;AAAAA;;YAGEN,IAAAO,aAAAA,CAAY,KAAZA;YAGAP,IAAAO,aAAAA,CAAY,QAAZA;YAGAP,IAAAO,aAAAA,CAAY,KAAZA;;AAMAC,YAAAA,0BAAAA,sBAAeC,MAAD,EAASC,GAAT,EAAcC,MAAd,EAA4BC,GAA1CJ;AAAAA,cAAAA;;;cAA4B,6BAAS;cAAK,uBAAM;cAC9CK,cAAUJ;cACVK,WAAOJ;cACPK,cAAUJ;cACVH,OAAAQ,CAAAA,WAAOJ,GAAPI;YAJFR,CAAAA,IAAAA;;AAUAS,YAAAA,oBAAAA,gBAASC,WAATD,GAAAA,MAAAA,IAAAA,wCAAAA;AAAAA,cAAAA;;cACEA,OAAqCE,SAAdA,SAAvBL,QAAIG,MAAAA,CAAMC,WAAND,CAAmBE,EAAEnB,IAAAoB,aAAAA,CAAAA,CAAFD,CAAcA,EAAE,CAAA,KAAAH,QAAA,qCAAA,EAAA,MAAA,CAAWE,WAAX,EAAwB,GAAxB,CAAA,CAA4BG,MAAAA,CAAAA,CAA9BF,CADvCF;gBAAAA;gBAAAA;cAAAA;YAAAA,CAAAA;;AAMAK,YAAAA,qBAAAA,iBAAAA;AAAAA,cAAAA;;cACE,IAAA,QAAGP,WAAH,CAAA;gBACEO,OAACA,YAAD,GAAA,CAAaP,WAAb,CAAA,GAAqBO,GAArB,GAAA,CAAwBR,QAAIQ,OAAAA,CAAAA,CAA5B,CAAA,GAAmCA,GAAnC,GAAA,CAAsCN,QAAIM,OAAAA,CAAAA,CAA1C,CAAA,GAAiDA;cADnD;gBAGEA,OAACA,WAAD,GAAA,CAAYR,QAAIQ,OAAAA,CAAAA,CAAhB,CAAA,GAAuBA;cAHzB;YADFA,CAAAA;;AAQAC,YAAAA,oBAAAA,yBAASL,WAAD,EAAcM,UAAtBD,GAAAA,MAAAA,IAAAA,wCAAAA;AAAAA,cAAAA;;;cACEC,aAAaC,gBAAUC,KAAAA,CAAKF,UAAf,EAA2BN,WAAjBQ;cACvBC,QAAQb,QAAIS,MAAAA,CAAML,WAAV,EAAuBM,UAAnBD;cAEZK,gBACE,CAAO,CAAA,QAA6BC,OAA7BL,UAAUM,cAAAA,CAAAA,CAAaC,MAAAA,CAAAA,CAAMF,EAAGG,CAAHH,CAA7B,CAAA,IAAA,CAAA,QAAqCf,QAAImB,UAAAA,CAAOC,IAAAC,UAAAD,aAAPD,CAAzC,CAAA,CAAA,CAAP,GAAA,CAAA,GAAA,IAAA,CACEnB,QAAIsB,QAAAA,CAAAA,CADN,CAAA;cAIFC,SACE,CAAA,QAAGtB,WAAH,CAAA,GAAA,CACE