Dice::Randomizer]\n        # @param game_system [BCDice::Base]\n        def initialize(rand_source, game_system)\n          @rand_source = rand_source\n          @game_system = game_system\n          @rand_results = []\n        end\n\n        # ダイスを振る\n        # @param times [Integer] ダイス数\n        # @param sides [Integer] 面数\n        # @return [Array<Integer>] 出目の配列\n        def roll(times, sides)\n          dice_list =\n            if sides == 66\n              Array.new(times) { @rand_source.roll_d66(@game_system.d66_sort_type) }\n            elsif sides == 9 && @game_system.enabled_d9?\n              Array.new(times) { @rand_source.roll_d9() }\n            else\n              @rand_source.roll_barabara(times, sides)\n            end\n\n          dice_list.sort! if @game_system.sort_add_dice?\n          rand_results = dice_list.map { |value| RandResult.new(sides, value) }\n          @rand_results.concat(rand_results)\n\n          dice_list\n        end\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "<module:BCDice>", "<module:CommonCommand>", "<module:AddDice>", "<class:Randomizer>", "self", "attr_reader", "Struct", "new", "initialize", "rand_source", "game_system", "@rand_source", "@game_system", "@rand_results", "roll", "times", "sides", "dice_list", "66", "Array", "block in roll", "block (2 levels) in roll", "roll_d66", "d66_sort_type", "9", "enabled_d9?", "roll_d9", "roll_barabara", "sort_add_dice?", "sort!", "rand_results", "map", "value", "RandResult", "concat"], :mappings=>"AAAAA,4DAAAA,gBAAAA;EAAAA;;EAEAA,OAAAC;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;MACEA,OAAAC;MAAAA;;QAAAA;;QACEA,OAAAC;QAAAA;;UAAAA;;AAAAA;;UACEC,IAAAC,aAAAA,CAAY,cAAZA;UAEA,sCAAaC,YAAMC,KAAAA,CAAK,OAAX,EAAmB,OAAbA,CAAnB;;AAIAC,UAAAA,0BAAAA,sBAAeC,WAAD,EAAcC,WAA5BF;AAAAA,YAAAA;;;YACEG,mBAAeF;YACfG,mBAAeF;YACfF,OAAAK,CAAAA,oBAAgB,EAAhBA;UAHFL,CAAAA;UAUAL,OAAAW,oBAAAA,gBAASC,KAAD,EAAQC,KAAhBF;AAAAA,YAAAA;;;YACEG,YACE,CAAA,MAAGD,KAAH,EAAYE,EAAZ,CAAA,GAAA,CACOX,MAALY,WAAKZ,OAAAA,EAAAA,CAAKQ,KAALR,CAAAA,EAALa,aAAAA,EAAAC;AAAAA;AAAAA;;cAAmBA,OAAAV,gBAAYW,UAAAA,CAAUV,gBAAYW,eAAAA,CAAAA,CAAtBD,CAA/BF,CAAAA,GAAAA,SAAAA,CAAKb,CADP,IAEA,CAAM,CAAA,MAAAS,KAAA,EAASQ,CAAT,CAAA,IAAA,CAAA,QAAcZ,gBAAYa,gBAAAA,CAAAA,CAA1B,CAAA,CAAA,CAAN,GAAA,CACOlB,MAALY,WAAKZ,OAAAA,EAAAA,CAAKQ,KAALR,CAAAA,EAALa,aAAAA,EAAAC;AAAAA;;cAAmBA,OAAAV,gBAAYe,SAAAA,CAAAA,CAA/BN,CAAAA,GAAAA,SAAAA,CAAKb,CADP,IAAA,CAGEI,gBAAYgB,eAAAA,CAAeZ,KAA3B,EAAkCC,KAAtBW,CAHd,CAAA,CAFA;YAQF,IAAA,QAAmBf,gBAAYgB,mBAAAA,CAAAA,CAA/B,CAAA;cAAAX,SAASY,UAAAA,CAAAA;YAAT;YACAC,eAAwBC,MAATd,SAASc,OAAAA,EAAAA,EAAAA,EAATX,aAAiBY,KAAjBZ;;cAAiB;cAAOC,OAAAY,gBAAU1B,KAAAA,CAAKS,KAAf,EAAsBgB,KAAZzB,EAAlCa,CAASW;YACxBlB,iBAAaqB,QAAAA,CAAQJ,YAARI;YAEbpB,OAAAG;UAdFH,CAAAA;QAjBFX,GAAAA,WAAAA,EAAAA,IAAAA;MADFD,GAAAA,WAAAA;IADFD,GAAAA,WAAAA;EADFD,GAAAA,WAAAA;AAFAD;"}}, {:offset=>{:line=>2067, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["bcdice/common_command/add_dice.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nrequire \"bcdice/normalize\"\nrequire \"bcdice/common_command/add_dice/parser\"\nrequire \"bcdice/common_command/add_dice/randomizer\"\n\nmodule BCDice\n  module CommonCommand\n    module AddDice\n      PREFIX_PATTERN = /[+\\-(]*(\\d+|D\\d+)/.freeze\n\n      class << self\n        def eval(command, game_system, randomizer)\n          cmd = Parser.parse(command)\n          cmd&.eval(game_system, randomizer)\n        end\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "self", "require", "<module:BCDice>", "<module:CommonCommand>", "<module:AddDice>", "freeze", "eval", "command", "game_system", "randomizer", "cmd", "Parser", "parse"], :mappings=>"AAAAA,iDAAAA,gBAAAA;EAAAA;;;EAEAC,IAAAC,SAAAA,CAAQF,kBAARE;EACAD,IAAAC,SAAAA,CAAQF,uCAARE;EACAD,IAAAC,SAAAA,CAAQF,2CAARE;EAEAF,OAAAG;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;MACEA,OAAAC;MAAAA;;QAAAA;;;QACE,0CAAiB,mBAAmBC,QAAAA,CAAAA,CAApC;QAEAD,OAAA;UAAA;;UACE,OAAAE,oBAAAA,iBAASC,OAAD,EAAUC,WAAV,EAAuBC,UAA/BH,GAAAA,MAAAA,IAAAA,wCAAAA;AAAAA,YAAAA;;;YACEI,MAAMC,YAAMC,OAAAA,CAAOL,OAAPK;YACZN,OAAA,CAAA,KAAAI,GAAA,qCAAA,EAAA,MAAA,CAAUF,WAAV,EAAuBC,UAAvB,CAAA,EAFFH;cAAAA;cAAAA;YAAAA;UAAAA,CAAAA;QADF,4BAASN,IAAT;MAHFI,GAAAA,WAAAA;IADFD,GAAAA,WAAAA;EADFD,GAAAA,WAAAA;AANAH;"}}, {:offset=>{:line=>2110, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["bcdice/common_command/reroll_dice/node.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nmodule BCDice\n  module CommonCommand\n    module RerollDice\n      module Node\n        class Command\n          def initialize(secret:, notations:, source:, cmp_op: nil, target_number: nil, reroll_cmp_op: nil, reroll_threshold: nil)\n            @secret = secret\n            @notations = notations\n            @cmp_op = cmp_op\n            @target_number_node = target_number\n            @reroll_cmp_op = reroll_cmp_op\n            @reroll_threshold_node = reroll_threshold\n            @source = source\n          end\n\n          def eval(game_system, randomizer)\n            round_type = game_system.round_type\n            cmp_op = @cmp_op || game_system.default_cmp_op\n            reroll_cmp_op = @reroll_cmp_op || cmp_op || :>=\n\n            target_number =\n              @target_number_node&.eval(round_type) ||\n              game_system.default_target_number\n\n            reroll_threshold =\n              @reroll_threshold_node&.eval(round_type) ||\n              game_system.reroll_dice_reroll_threshold ||\n              target_number\n\n            reroll_condition = RerollCondition.new(reroll_cmp_op, reroll_threshold)\n\n            dice_queue = @notations.map { |node| node.to_dice(round_type) }\n            unless dice_queue.all? { |d| reroll_condition.valid?(d.sides) }\n              return result_with_text(\"\#{@source} ＞ 条件が間違っています。2R6>=5 あるいは 2R6[5] のように振り足し目標値を指定してください。\")\n            end\n\n            dice_list_list = roll(\n              dice_queue,\n              randomizer,\n              reroll_condition,\n              game_system.sort_barabara_dice?\n            )\n\n            dice_list = dice_list_list.flatten\n\n            # 振り足し分は出目1の個数をカウントしない\n            one_count = dice_list_list\n                        .take(@notations.size)\n                        .flatten\n                        .count(1)\n\n            success_count =\n              if cmp_op\n                dice_list.count { |val| val.send(cmp_op, target_number) }\n              else\n                0\n              end\n\n            sequence = [\n              expr(round_type, reroll_condition, cmp_op, target_number),\n              dice_list_list.map { |list| list.join(\",\") }.join(\" + \"),\n              \"成功数\#{success_count}\",\n              game_system.grich_text(one_count, dice_list.size, success_count),\n            ].compact\n\n            result_with_text(sequence.join(\" ＞ \"))\n          end\n\n          private\n\n          # ダイスロールを行う\n          # @param dice_queue [Array<Dice>] ダイスキュー\n          # @param randomizer [Randomizer] 乱数生成器\n          # @param reroll_condition [RerollCondition] 振り足し条件\n          # @param sort [Boolean] 出目を並び替えるか\n          # @return [Array<Array<Integer>>]\n          def roll(dice_queue, randomizer, reroll_condition, sort)\n            dice_list_list = []\n            loop_count = 0\n\n            while !dice_queue.empty? && loop_count < REROLL_LIMIT\n              dice = dice_queue.shift\n              loop_count += 1\n\n              dice_list = dice.roll(randomizer)\n              dice_list.sort! if sort\n              dice_list_list.push(dice_list)\n\n              reroll_count = dice_list.count { |val| reroll_condition.reroll?(val) }\n              if reroll_count > 0\n                dice_queue.push(Dice.new(reroll_count, dice.sides))\n              end\n            end\n\n            return dice_list_list\n          end\n\n          def expr(round_type, reroll_condition, cmp_op, target_number)\n            notation = @notations.map { |n| n.to_dice(round_type) }.join(\"+\")\n\n            reroll_cmp_op_text =\n              if reroll_condition.cmp_op == cmp_op\n                \"\"\n              else\n                Format.comparison_operator(reroll_condition.cmp_op)\n              end\n\n            cmp_op_text = Format.comparison_operator(cmp_op)\n\n            \"(\#{notation}[\#{reroll_cmp_op_text}\#{reroll_condition.threshold}]\#{cmp_op_text}\#{target_number})\"\n          end\n\n          def result_with_text(text)\n            Result.new.tap do |r|\n              r.secret = @secret\n              r.text = text\n            end\n          end\n        end\n\n        # 振り足し条件を表すクラス。\n        class RerollCondition\n          # @return [Symbol] 比較演算子\n          attr_reader :cmp_op\n          # @return [Integer] 振り足しの閾値\n          attr_reader :threshold\n\n          # @param cmp_op [Symbol] 比較演算子\n          # @param threshold [Integer] 振り足しの閾値\n          def initialize(cmp_op, threshold)\n            @cmp_op = cmp_op\n            @threshold = threshold\n          end\n\n          # @param sides [Integer] ダイスの面数\n          # @return [Boolean] 振り足し条件が妥当か\n          def valid?(sides)\n            return false unless @threshold\n\n            case @cmp_op\n            when :<=\n              @threshold < sides\n            when :<\n              @threshold <= sides\n            when :>=\n              @threshold > 1\n            when :>\n              @threshold >= 1\n            when :'!='\n              (1..sides).include?(@threshold)\n            else # :==\n              true\n            end\n          end\n\n          # @param value [Integer] 出目\n          # @return [Boolean] 振り足しを行うべきか\n          def reroll?(value)\n            value.send(@cmp_op, @threshold)\n          end\n        end\n\n        class Notation\n          def initialize(times, sides)\n            @times = times\n            @sides = sides\n          end\n\n          def to_dice(round_type)\n            times = @times.eval(round_type)\n            sides = @sides.eval(round_type)\n\n            Dice.new(times, sides)\n          end\n        end\n\n        class Dice\n          attr_reader :times, :sides\n\n          def initialize(times, sides)\n            @times = times\n            @sides = sides\n          end\n\n          def roll(randomizer)\n            randomizer.roll_barabara(times, sides)\n          end\n\n          def to_s\n            \"\#{times}R\#{sides}\"\n          end\n        end\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "<module:BCDice>", "<module:CommonCommand>", "<module:RerollDice>", "<module:Node>", "<class:Command>", "initialize", "$kwargs", "@secret", "secret", "@notations", "notations", "@cmp_op", "cmp_op", "@target_number_node", "target_number", "@reroll_cmp_op", "reroll_cmp_op", "@reroll_threshold_node", "reroll_threshold", "@source", "source", "eval", "game_system", "randomizer", "round_type", "$ret_or_1", "default_cmp_op", "$ret_or_2", "default_target_number", "reroll_dice_reroll_threshold", "reroll_condition", "RerollCondition", "new", "dice_queue", "map", "block in eval", "node", "block (2 levels) in eval", "to_dice", "all?", "d", "valid?", "sides", "self", "result_with_text", "dice_list_list", "roll", "sort_barabara_dice?", "dice_list", "flatten", "one_count", "take", "size", "count", "1", "success_count", "val", "send", "0", "sequence", "expr", "list", "join", "grich_text", "compact", "private", "sort", "loop_count", "empty?", "!", "<", "REROLL_LIMIT", "dice", "shift", "+", "sort!", "push", "reroll_count", "block in roll", "block (2 levels) in roll", "reroll?", ">", "Dice", "notation", "block in expr", "n", "block (2 levels) in expr", "reroll_cmp_op_text", "Format", "comparison_operator", "cmp_op_text", "threshold", "text", "tap", "Result", "block in result_with_text", "r", "block (2 levels) in result_with_text", "secret=", "text=", "<class:RerollCondition>", "attr_reader", "@threshold", "<=", ">=", "include?", "value", "<class:Notation>", "times", "@times", "@sides", "<class:Dice>", "roll_barabara", "to_s"], :mappings=>"AAAAA,yDAAAA,gBAAAA;EAAAA;;EAEAA,OAAAC;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;MACEA,OAAAC;MAAAA;;QAAAA;;QACEA,OAAAC;QAAAA;;UAAAA;;;UACEC;UAAAA;;YAAAA;;AAAAA;;;AACEC,YAAAA,0BAAAA,sBAPVC,OAOUD;AAAAA,cAAAA;;;cAPV;cAOyB;cAAS;cAAY;;cAAS,kCAAA,6BAAQ;;cAAK,gDAAA,2CAAe;;cAAK,gDAAA,2CAAe;;cAAK,sDAAA,iDAAkB;cAClHE,cAAUC;cACVC,iBAAaC;cACbC,cAAUC;cACVC,0BAAsBC;cACtBC,qBAAiBC;cACjBC,6BAAyBC;cACzBb,OAAAc,CAAAA,cAAUC,MAAVD;YAPFd,CAAAA;;AAUAgB,YAAAA,oBAAAA,yBAASC,WAAD,EAAcC,UAAtBF,GAAAA,MAAAA,IAAAA,wCAAAA;AAAAA,cAAAA;;;cACEG,aAAaF,WAAWE,YAAAA,CAAAA;cACxBZ,SAAS,CAAA,QAAAa,CAAAA,YAAAd,WAAAc,CAAA,CAAA,GAAA,CAAA,SAAA,IAAA,CAAWH,WAAWI,gBAAAA,CAAAA,CAAtB,CAAA;cACTV,gBAAgB,CAAA,QAAAS,CAAAA,YAAA,CAAA,QAAAE,CAAAA,YAAAZ,kBAAAY,CAAA,CAAA,GAAA,CAAA,SAAA,IAAA,CAAkBf,MAAlB,CAAA,CAAAa,CAAA,CAAA,GAAA,CAAA,SAAA,IAAA,CAA4B,IAA5B,CAAA;cAEhBX,gBACE,CAAA,QAAAW,CAAAA,YAAA,CAAA,KAAAZ,uBAAA,qCAAA,EAAA,MAAA,CAA0BW,UAA1B,CAAA,CAAAC,CAAA,CAAA,GAAA,CAAA,SAAA,IAAA,CACAH,WAAWM,uBAAAA,CAAAA,CADX,CAAA;cAGFV,mBACE,CAAA,QAAAO,CAAAA,YAAA,CAAA,QAAAE,CAAAA,YAAA,CAAA,KAAAV,0BAAA,qCAAA,EAAA,MAAA,CAA6BO,UAA7B,CAAA,CAAAG,CAAA,CAAA,GAAA,CAAA,SAAA,IAAA,CACAL,WAAWO,8BAAAA,CAAAA,CADX,CAAA,CAAAJ,CAAA,CAAA,GAAA,CAAA,SAAA,IAAA,CAEAX,aAFA,CAAA;cAIFgB,mBAAmBC,qBAAeC,KAAAA,CAAKhB,aAApB,EAAmCE,gBAApBc;cAElCC,aAAuBC,MAAVzB,cAAUyB,OAAAA,EAAAA,EAAAA,EAAVC,aAAkBC,IAAlBD;;gBAAkB;gBAAME,OAAAD,IAAIE,SAAAA,CAASd,UAATc,EAA5BH,CAAUD;cACvB,KAAA,QAAiBK,MAAVN,UAAUM,QAAAA,EAAAA,EAAAA,EAAVJ,aAAmBK,CAAnBL;;gBAAmB;gBAAGE,OAAAP,gBAAgBW,WAAAA,CAAQD,CAACE,OAAAA,CAAAA,CAATD,EAAtCN,CAAUI,CAAjB,CAAA;gBACE,OAAOI,IAAAC,kBAAAA,CAAiB,EAAA,GAAA,CAAGzB,WAAH,CAAA,GAAWE,wDAA5BuB;cADT;cAIAC,iBAAiBF,IAAAG,MAAAA,CACfb,UADe,EAEfV,UAFe,EAGfO,gBAHe,EAIfR,WAAWyB,wBAAAA,CAAAA,CAJID;cAOjBE,YAAYH,cAAcI,SAAAA,CAAAA;cAG1BC,YAAYL,cACAM,MAAAA,CAAM1C,cAAU2C,MAAAA,CAAAA,CAAhBD,CACAF,SAAAA,CAAAA,CACAI,OAAAA,CAAOC,CAAPD;cAEZE,gBACE,CAAA,QAAG3C,MAAH,CAAA,GAAA,CACWyC,MAATL,SAASK,SAAAA,EAAAA,EAAAA,EAATlB,a