IAAAC,SAAAA,CAAQF,4CAARE;EAEAF,OAAAG;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;MACEA,OAAAC;MAAAA;;QAAAA;;;QACE,0CAAiB,SAASC,QAAAA,CAAAA,CAA1B;QAEAD,OAAA;UAAA;;UACE,OAAAE,oBAAAA,iBAASC,OAAD,EAAUC,WAAV,EAAuBC,UAA/BH,GAAAA,MAAAA,IAAAA,wCAAAA;AAAAA,YAAAA;;;YACEI,MAAMC,YAAMC,OAAAA,CAAOL,OAAPK;YACZN,OAAA,CAAA,KAAAI,GAAA,qCAAA,EAAA,MAAA,CAAUF,WAAV,EAAuBC,UAAvB,CAAA,EAFFH;cAAAA;cAAAA;YAAAA;UAAAA,CAAAA;QADF,4BAASN,IAAT;MAHFI,GAAAA,WAAAA;IADFD,GAAAA,WAAAA;EADFD,GAAAA,WAAAA;AAJAH;"}}, {:offset=>{:line=>2881, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["bcdice/result.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nmodule BCDice\n  # ダイスロールの結果を表すクラス\n  #\n  # コマンドの結果の文字列や、成功／失敗／クリティカル／ファンブルの情報を保持する。\n  # 成功／失敗は同時に発生しないこととする。\n  # 成功／失敗のペアとクリティカル、ファンブルの三者は独立した要素とし、\n  # 「クリティカルだが失敗」や「ファンブルだが成功でも失敗でもない」を許容する。\n  class Result\n    class << self\n      # +success+ が設定された +Result+ を作成する\n      #\n      # @param text [String]\n      # @return [Result]\n      def success(text)\n        new.tap do |r|\n          r.text = text\n          r.success = true\n        end\n      end\n\n      # +failure+ が設定された +Result+ を作成する\n      #\n      # @param text [String]\n      # @return [Result]\n      def failure(text)\n        new.tap do |r|\n          r.text = text\n          r.failure = true\n        end\n      end\n\n      # +success+ と +critical+ が設定された +Result+ を作成する\n      #\n      # @param text [String]\n      # @return [Result]\n      def critical(text)\n        new.tap do |r|\n          r.text = text\n          r.critical = true\n          r.success = true\n        end\n      end\n\n      # +failure+ と +fumble+ が設定された +Result+ を作成する\n      #\n      # @param text [String]\n      # @return [Result]\n      def fumble(text)\n        new.tap do |r|\n          r.text = text\n          r.fumble = true\n          r.failure = true\n        end\n      end\n\n      # その後の判定で何もすることがないことを示すために利用する\n      #\n      # @return [:nothing]\n      def nothing\n        :nothing\n      end\n    end\n\n    # @param text [String | nil]\n    def initialize(text = nil)\n      @text = text\n      @rands = nil\n      @detailed_rands = nil\n      @secret = false\n      @success = false\n      @failure = false\n      @critical = false\n      @fumble = false\n    end\n\n    attr_accessor :text, :rands, :detailed_rands\n    attr_writer :secret, :success, :failure, :critical, :fumble\n\n    # @return [Boolean]\n    def secret?\n      @secret\n    end\n\n    # @return [Boolean]\n    def success?\n      @success\n    end\n\n    # @return [Boolean]\n    def failure?\n      @failure\n    end\n\n    # @return [Boolean]\n    def critical?\n      @critical\n    end\n\n    # @return [Boolean]\n    def fumble?\n      @fumble\n    end\n\n    # @param condition [Boolean]\n    # @return [void]\n    def condition=(condition)\n      @success = condition\n      @failure = !condition\n    end\n  end\nend\n"], :names=>["<top (required)>", "<module:BCDice>", "<class:Result>", "success", "text", "tap", "self", "new", "block in success", "r", "block (2 levels) in success", "text=", "success=", "failure", "block in failure", "block (2 levels) in failure", "failure=", "critical", "block in critical", "block (2 levels) in critical", "critical=", "fumble", "block in fumble", "block (2 levels) in fumble", "fumble=", "nothing", "initialize", "@text", "@rands", "@detailed_rands", "@secret", "@success", "@failure", "@critical", "@fumble", "attr_accessor", "attr_writer", "secret?", "success?", "failure?", "critical?", "fumble?", "condition=", "condition", "!"], :mappings=>"AAAAA,gCAAAA,gBAAAA;EAAAA;;EAEAA,OAAAC;EAAAA;;IAAAA;;IAOEA,OAAAC;IAAAA;;MAAAA;;;MACE;;;;AAKEC,QAAAA,uBAAAA,mBAAYC,IAAZD;AAAAA,UAAAA;;UACEA,OAAGE,MAAHC,IAAAC,KAAAA,CAAAA,CAAGF,OAAAA,EAAAA,EAAAA,EAAHG,aAAYC,CAAZD,EAAAE;;;YAAY;YACVD,CAACE,UAAAA,CAAQP,IAARO;YACDD,OAACE,MAAAA,CAAW,IAAXA,CAAAA,EAAAA,MAADH,CAACG,YAAAA,EAAAA,EAAAA,CAAAA,EAAAA,mBAFHJ,CAAGH;QADLF,CAAAA;;AAWAU,QAAAA,uBAAAA,mBAAYT,IAAZS;AAAAA,UAAAA;;UACEA,OAAGR,MAAHC,IAAAC,KAAAA,CAAAA,CAAGF,OAAAA,EAAAA,EAAAA,EAAHS,aAAYL,CAAZK,EAAAC;;;YAAY;YACVN,CAACE,UAAAA,CAAQP,IAARO;YACDI,OAACC,MAAAA,CAAW,IAAXA,CAAAA,EAAAA,MAADP,CAACO,YAAAA,EAAAA,EAAAA,CAAAA,EAAAA,mBAFHF,CAAGT;QADLQ,CAAAA;;AAWAI,QAAAA,wBAAAA,oBAAab,IAAba;AAAAA,UAAAA;;UACEA,OAAGZ,MAAHC,IAAAC,KAAAA,CAAAA,CAAGF,OAAAA,EAAAA,EAAAA,EAAHa,aAAYT,CAAZS,EAAAC;;;YAAY;YACVV,CAACE,UAAAA,CAAQP,IAARO;YACDF,CAACW,cAAAA,CAAY,IAAZA;YACDD,OAACP,MAAAA,CAAW,IAAXA,CAAAA,EAAAA,MAADH,CAACG,YAAAA,EAAAA,EAAAA,CAAAA,EAAAA,mBAHHM,CAAGb;QADLY,CAAAA;;AAYAI,QAAAA,sBAAAA,kBAAWjB,IAAXiB;AAAAA,UAAAA;;UACEA,OAAGhB,MAAHC,IAAAC,KAAAA,CAAAA,CAAGF,OAAAA,EAAAA,EAAAA,EAAHiB,aAAYb,CAAZa,EAAAC;;;YAAY;YACVd,CAACE,UAAAA,CAAQP,IAARO;YACDF,CAACe,YAAAA,CAAU,IAAVA;YACDD,OAACP,MAAAA,CAAW,IAAXA,CAAAA,EAAAA,MAADP,CAACO,YAAAA,EAAAA,EAAAA,CAAAA,EAAAA,mBAHHM,CAAGjB;QADLgB,CAAAA;QAWA,OAAAI,uBAAAA,YACE,SADFA,CAAAA;MAlDF,4BAASnB,IAAT;;AAwDAoB,MAAAA,0BAAAA,sBAAetB,IAAfsB;AAAAA,QAAAA;;;QAAe,yBAAO;QACpBC,YAAQvB;QACRwB,aAAS;QACTC,sBAAkB;QAClBC,cAAU;QACVC,eAAW;QACXC,eAAW;QACXC,gBAAY;QACZP,OAAAQ,CAAAA,cAAU,KAAVA;MARFR,CAAAA,IAAAA;MAWApB,IAAA6B,eAAAA,CAAc,MAAd,EAAqB,OAArB,EAA6B,gBAA7BA;MACA7B,IAAA8B,aAAAA,CAAY,QAAZ,EAAqB,SAArB,EAA+B,SAA/B,EAAyC,UAAzC,EAAoD,QAApDA;;AAGAC,MAAAA,uBAAAA,aACE,QADFA,CAAAA;;AAKAC,MAAAA,wBAAAA,aACE,SADFA,CAAAA;;AAKAC,MAAAA,wBAAAA,aACE,SADFA,CAAAA;;AAKAC,MAAAA,yBAAAA,aACE,UADFA,CAAAA;;AAKAC,MAAAA,uBAAAA,aACE,QADFA,CAAAA;MAMAvC,OAAAwC,0BAAAA,gCAAeC,SAAfD;AAAAA,QAAAA;;;QACEX,eAAWY;QACXD,OAAAV,CAAAA,eAAYW,SAADC,MAAAA,CAAAA,CAAXZ;MAFFU,CAAAA;IAlGFxC,GAAAA,WAAAA,EAAAA,IAAAA;EAPFD,GAAAA,WAAAA;AAFAD;"}}, {:offset=>{:line=>2984, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["bcdice/common_command/tally_dice/node.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nrequire \"bcdice/result\"\n\nmodule BCDice\n  module CommonCommand\n    module TallyDice\n      # 個数カウントダイスを表すノードをまとめるモジュール\n      module Node\n        # 個数カウントダイス：コマンドのノード\n        class Command\n          # 最大面数\n          MAX_SIDES = 20\n\n          # @param secret [Boolean] シークレットダイスか\n          # @param notation [Notation] ダイス表記\n          def initialize(secret:, notation:)\n            @secret = secret\n            @notation = notation\n          end\n\n          # @param game_system [Base] ゲームシステム\n          # @param randomizer [Randomizer] ランダマイザ\n          # @return [Result, nil]\n          def eval(game_system, randomizer)\n            dice = @notation.to_dice(game_system.round_type)\n            unless dice.valid?\n              return nil\n            end\n\n            if dice.sides > MAX_SIDES\n              return Result.new(\"(\#{dice}) ＞ 面数は1以上、\#{MAX_SIDES}以下としてください\")\n            end\n\n            values = dice.roll(randomizer)\n\n            values_str = (game_system.sort_barabara_dice? ? values.sort : values)\n                         .join(\",\")\n\n            # TODO: Ruby 2.7以降のみサポートするようになった場合\n            # Enumerable#tally で書く\n            values_count = values\n                           .group_by(&:itself)\n                           .transform_values(&:length)\n\n            values_count_strs = (1..dice.sides).map do |v|\n              count = values_count.fetch(v, 0)\n\n              next nil if count == 0 && !dice.show_zeros?\n\n              \"[\#{v}]×\#{values_count.fetch(v, 0)}\"\n            end\n\n            sequence = [\n              \"(\#{dice})\",\n              values_str,\n              values_count_strs.compact.join(\", \"),\n            ].compact\n\n            Result.new.tap do |r|\n              r.secret = @secret\n              r.text = sequence.join(\" ＞ \")\n            end\n          end\n        end\n\n        # 個数カウントダイス：ダイス表記のノード\n        class Notation\n          # @return [Integer] 振る回数\n          attr_reader :times\n          # @return [Integer] 面数\n          attr_reader :sides\n          # @return [Boolean] 個数0を表示するか\n          attr_reader :show_zeros\n\n          # @param times [#eval] 振る回数\n          # @param sides [#eval] 面数\n          # @param show_zeros [Boolean] 個数0を表示するか\n          def initialize(times:, sides:, show_zeros:)\n            @times = times\n            @sides = sides\n            @show_zeros = show_zeros\n          end\n\n          # @param round_type [Symbol] 除算の端数処理方法\n          # @return [Dice]\n          def to_dice(round_type)\n            times = @times.eval(round_type)\n            sides = @sides.eval(round_type)\n\n            Dice.new(times: times, sides: sides, show_zeros: @show_zeros)\n          end\n        end\n\n        # 個数カウントダイス：ダイスのノード\n        class Dice\n          # @return [Integer] 振る回数\n          attr_reader :times\n          # @return [Integer] 面数\n          attr_reader :sides\n          # @return [Boolean] 個数0を表示するか\n          attr_reader :show_zeros\n\n          alias show_zeros? show_zeros\n\n          # @param times [Integer] 振る回数\n          # @param sides [Integer] 面数\n          def initialize(times:, sides:, show_zeros:)\n            @times = times\n            @sides = sides\n            @show_zeros = show_zeros\n          end\n\n          # @return [Boolean] ダイスとして有効（振る回数、面数ともに正の数）か\n          def valid?\n            @times > 0 && @sides > 0\n          end\n\n          # ダイスを振る\n          # @param randomizer [BCDice::Randomizer] ランダマイザ\n          # @return [Array<Integer>] 出目の配列\n          def roll(randomizer)\n            randomizer.roll_barabara(@times, @sides)\n          end\n\n          # @return [String]\n          def to_s\n            show_zeros_symbol = @show_zeros ? \"Z\" : \"Y\"\n            \"\#{@times}T\#{show_zeros_symbol}\#{@sides}\"\n          end\n        end\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "self", "require", "<module:BCDice>", "<module:CommonCommand>", "<module:TallyDice>", "<module:Node>", "<class:Command>", "20", "initialize", "$kwargs", "@secret", "secret", "@notation", "notation", "eval", "game_system", "randomizer", "dice", "to_dice", "round_type", "valid?", ">", "sides", "MAX_SIDES", "Result", "new", "values", "roll", "values_str", "sort_barabara_dice?", "sort", "join", "values_count", "transform_values", "group_by", "to_proc", "values_count_strs", "map", "1", "block in eval", "v", "block (2 levels) in eval", "count", "fetch", "0", "show_zeros?", "sequence", "compact", "tap", "r", "secret=", "text=", "<class:Notation>", "attr_reader", "@times", "times", "@sides", "@show_zeros", "show_zeros", "Dice", "<class:Dice>", "$ret_or_1", "roll_barabara", "to_s", "show_zeros_symbol"], :mappings=>"AAAAA,wDAAAA,gBAAAA;EAAAA;;;EAEAC,IAAAC,SAAAA,CAAQF,eAARE;EAEAF,OAAAG;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;MACEA,OAAAC;MAAAA;;QAAAA;;QAEEA,OAAAC;QAAAA;;UAAAA;;;UAEEC;UAAAA;;YAAAA;;AAAAA;;YAEE,qCAAYC,EAAZ;;AAIAC,YAAAA,0BAAAA,sBAhBVC,OAgBUD;AAAAA,cAAAA;;;cAhBV;cAgByB;cAAS;cACtBE,cAAUC;cACVH,OAAAI,CAAAA,gBAAYC,QAAZD;YAFFJ,CAAAA;YAQAF,OAAAQ,oBAAAA,yBAASC,WAAD,EAAcC,UAAtBF;AAAAA,cAAAA;;;cACEG,OAAOL,aAASM,SAAAA,CAASH,WAAWI,YAAAA,CAAAA,CAApBD;cAChB,KAAA,QAAOD,IAAIG,WAAAA,CAAAA,CAAX,CAAA;gBACE,OAAO;cADT;cAIA,IAAA,QAAcC,OAAXJ,IAAIK,OAAAA,CAAAA,CAAOD,EAAEE,eAAFF,CAAd,CAAA;gBACE,OAAOG,YAAMC,KAAAA,CAAMX,GAAD,GAAA,CAAIG,IAAJ,CAAA,GAASH,aAAT,GAAA,CAAsBS,eAAtB,CAAA,GAAgCT,WAArCW;cADf;cAIAC,SAAST,IAAIU,MAAAA,CAAMX,UAANW;cAEbC,aAAc,CAAA,QAAAb,WAAWc,wBAAAA,CAAAA,CAAX,CAAA,GAAA,CAAkCH,MAAMI,MAAAA,CAAAA,CAAxC,IAAA,CAAgDJ,MAAhD,CAAA,CACDK,MAAAA,CAAMjB,GAANiB;cAIbC,eAEeC,MADAC,MADAR,MACAQ,YAAAA,EAAAA,EAAAA,EAAW,QAADC,SAAAA,CAAAA,CAAVD,CACAD,oBAAAA,EAAAA,EAAAA,EAAmB,QAADE,SAAAA,CAAAA,CAAlBF;cAEfG,oBAAmCC,MAAd,gBAAAC,CAAA,EAAGrB,IAAIK,OAAAA,CAAAA,CAAP,QAAce,OAAAA,EAAAA,EAAAA,EAAfE,aAAwBC,CAAxBD,EAAAE;;;gBAAwB;gBAC1CC,QAAQV,YAAYW,OAAAA,CAAOH,CAAnB,EAAsBI,CAAVD;gBAEpB,IAAY,CAAA,MAAAD,KAAA,EAASE,CAAT,CAAA,IAAA,CAAA,KAAe3B,IAAI4B,gBAAAA,CAAAA,CAAnB,CAAA,CAAA,CAAZ;kBAAA,OAAK;gBAAL;gBAEAJ,OAACA,GAAD,GAAA,CAAID,CAAJ,CAAA,GAAMC,IAAN,GAAA,CAAUT,YAAYW,OAAAA,CAAOH,CAAnB,EAAsBI,CAAVD,CAAtB,EALkBJ,CAAeF;cAQnCS,WAAW,CACRhC,GAAD,GAAA,CAAIG,IAAJ,CAAA,GAASH,GADA,EAETc,UAFS,EAGTQ,iBAAiBW,SAAAA,CAAAA,CAAQhB,MAAAA