dice/common_command/tally_dice/parser\"\n\nmodule BCDice\n  module CommonCommand\n    # 個数カウントダイスのモジュール\n    module TallyDice\n      PREFIX_PATTERN = /\\d+T[YZ]\\d+/.freeze\n\n      class << self\n        def eval(command, game_system, randomizer)\n          cmd = Parser.parse(command)\n          cmd&.eval(game_system, randomizer)\n        end\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "self", "require", "<module:BCDice>", "<module:CommonCommand>", "<module:TallyDice>", "freeze", "eval", "command", "game_system", "randomizer", "cmd", "Parser", "parse"], :mappings=>"AAAAA,mDAAAA,gBAAAA;EAAAA;;;EAEAC,IAAAC,SAAAA,CAAQF,yCAARE;EAEAF,OAAAG;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;MAEEA,OAAAC;MAAAA;;QAAAA;;;QACE,0CAAiB,aAAaC,QAAAA,CAAAA,CAA9B;QAEAD,OAAA;UAAA;;UACE,OAAAE,oBAAAA,iBAASC,OAAD,EAAUC,WAAV,EAAuBC,UAA/BH,GAAAA,MAAAA,IAAAA,wCAAAA;AAAAA,YAAAA;;;YACEI,MAAMC,YAAMC,OAAAA,CAAOL,OAAPK;YACZN,OAAA,CAAA,KAAAI,GAAA,qCAAA,EAAA,MAAA,CAAUF,WAAV,EAAuBC,UAAvB,CAAA,EAFFH;cAAAA;cAAAA;YAAAA;UAAAA,CAAAA;QADF,4BAASN,IAAT;MAHFI,GAAAA,WAAAA;IAFFD,GAAAA,WAAAA;EADFD,GAAAA,WAAAA;AAJAH;"}}, {:offset=>{:line=>3369, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["bcdice/common_command/calc/node.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nrequire \"bcdice/arithmetic/node\"\n\nmodule BCDice\n  module CommonCommand\n    module Calc\n      module Node\n        class Command\n          def initialize(secret:, expr:)\n            @secret = secret\n            @expr = expr\n          end\n\n          def eval(round_type)\n            value =\n              begin\n                @expr.eval(round_type).to_i\n              rescue ZeroDivisionError\n                \"ゼロ除算が発生したため計算できませんでした\"\n              end\n\n            output =\n              if @expr.is_a?(Arithmetic::Node::Parenthesis)\n                @expr.output\n              else\n                \"(\#{@expr.output})\"\n              end\n\n            Result.new.tap do |r|\n              r.secret = @secret\n              r.text = \"c\#{output} ＞ \#{value}\"\n            end\n          end\n        end\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "self", "require", "<module:BCDice>", "<module:CommonCommand>", "<module:Calc>", "<module:Node>", "<class:Command>", "initialize", "$kwargs", "@secret", "secret", "@expr", "expr", "eval", "round_type", "value", "to_i", "ZeroDivisionError", "output", "is_a?", "Arithmetic::Node::Parenthesis", "Arithmetic::Node", "Arithmetic", "tap", "Result", "new", "block in eval", "r", "block (2 levels) in eval", "secret=", "text="], :mappings=>"AAAAA,kDAAAA,gBAAAA;EAAAA;;;EAEAC,IAAAC,SAAAA,CAAQF,wBAARE;EAEAF,OAAAG;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;MACEA,OAAAC;MAAAA;;QAAAA;;QACEA,OAAAC;QAAAA;;UAAAA;;UACEA,OAAAC;UAAAA;;YAAAA;;AAAAA;;;AACEC,YAAAA,0BAAAA,sBATVC,OASUD;AAAAA,cAAAA;;;cATV;cASyB;cAAS;cACtBE,cAAUC;cACVH,OAAAI,CAAAA,YAAQC,IAARD;YAFFJ,CAAAA;YAKAD,OAAAO,oBAAAA,yBAASC,UAATD,GAAAA,MAAAA,IAAAA,wCAAAA;AAAAA,cAAAA;;;cACEE,QAEI,cAAA;gBAAAF,OAAAF,SAAKE,MAAAA,CAAMC,UAAND,CAAiBG,MAAAA,CAAAA;cAAtB;gBACF,sBAAO,CAAAC,uBAAA,CAAP;kBAAA;oBACEJ,OAAAA;kBADF;gBAAA,CADE;cAAA,CAAA;cAKJK,SACE,CAAA,QAAGP,SAAKQ,UAAAA,CAAOC,IAAAC,IAAAC,gBAAAD,SAAAD,gBAAPD,CAAR,CAAA,GAAA,CACER,SAAKO,QAAAA,CAAAA,CADP,IAAA,CAGGL,GAAD,GAAA,CAAIF,SAAKO,QAAAA,CAAAA,CAAT,CAAA,GAAiBL,GAHnB,CAAA;cAMFA,OAAUU,MAAVC,YAAMC,KAAAA,CAAAA,CAAIF,OAAAA,EAAAA,EAAAA,EAAVG,aAAmBC,CAAnBD,EAAAE;AAAAA;;;gBAAmB;gBACjBD,CAACE,YAAAA,CAAUpB,WAAVoB;gBACDD,OAACE,MAAAA,CAASF,GAAD,GAAA,CAAIV,MAAJ,CAAA,GAAWU,KAAX,GAAA,CAAgBb,KAAhB,CAARe,CAAAA,EAAAA,MAADH,CAACG,SAAAA,EAAAA,EAAAA,CAAAA,EAAAA,mBAFHJ,CAAAA,GAAAA,SAAAA,CAAUH,EAfZV;gBAAAA;gBAAAA;cAAAA;YAAAA,CAAAA;UANFP,GAAAA,WAAAA,EAAAA,IAAAA;QADFD,GAAAA,WAAAA;MADFD,GAAAA,WAAAA;IADFD,GAAAA,WAAAA;EADFD,GAAAA,WAAAA;AAJAH;"}}, {:offset=>{:line=>3444, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["bcdice/common_command/calc/parser.rb"], :sourcesContent=>["#\n# DO NOT MODIFY!!!!\n# This file is automatically gene