ings=>"AAAAA,6CAAAA,gBAAAA;EAAAA;;;EAEAC,IAAAC,SAAAA,CAAQF,mCAARE;EAEAF,OAAAG;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;MACEA,OAAAC;MAAAA;;QAAAA;;;QACE,0CAAiB,aAAaC,QAAAA,CAAAA,CAA9B;QAEAD,OAAA;UAAA;;UACE,OAAAE,oBAAAA,iBAASC,OAAD,EAAUC,WAAV,EAAuBC,WAA/BH,GAAAA,MAAAA,IAAAA,wCAAAA;AAAAA,YAAAA;;;YACEI,MAAMC,YAAMC,OAAAA,CAAOL,OAAPK;YACZN,OAAA,CAAA,KAAAI,GAAA,qCAAA,EAAA,MAAA,CAAUF,WAAWK,YAAAA,CAAAA,CAArB,CAAA,EAFFP;cAAAA;cAAAA;YAAAA;UAAAA,CAAAA;QADF,4BAASN,IAAT;MAHFI,GAAAA,WAAAA;IADFD,GAAAA,WAAAA;EADFD,GAAAA,WAAAA;AAJAH;"}}, {:offset=>{:line=>3653, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["bcdice/common_command/choice.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nrequire \"strscan\"\n\nmodule BCDice\n  module CommonCommand\n    # チョイスコマンド\n    #\n    # 列挙された項目の中から一つを選んで出力する。\n    #\n    # フォーマットは以下の通り\n    # choice[A,B,C,D]\n    # choice(A,B,C,D)\n    # choice A B C D\n    # choice(新クトゥルフ神話TRPG, ソード・ワールド2.5, Dungeons & Dragons)\n    #\n    # \"choice\"の次の文字によって区切り文字が変化する\n    #   \"[\" -> \",\" で区切る\n    #   \"(\" -> \",\" で区切る\n    #   \" \" -> /\\s+/ にマッチする文字列で区切る\n    #\n    # 各項目の前後に空白文字があった場合は除去される\n    #   choice[A, B,  C , D   ] は choice[A,B,C,D] と等価\n    #\n    # 項目が空文字列である場合、その項目は無視する\n    #   choice[A,,C] は choice[A,C] と等価\n    #\n    # フォーマットを選ぶことで、項目の文字列に()や,を含めることができる\n    #   choice A,B X,Y -> \"A,B\" と \"X,Y\" から選ぶ\n    #   choice(A[], B[], C[]) -> \"A[]\", \"B[]\", \"C[]\" から選ぶ\n    #   choice[A(), B(), C()] -> \"A()\", \"B()\", \"C()\" から選ぶ\n    #\n    # \"choice\"の後に数を指定することで、列挙した要素から重複なしで複数個を選ぶ\n    #   choice2[A,B,C] -> \"A\", \"B\", \"C\" から重複なしで2個選ぶ\n    #\n    # 指定したい要素が「AからD」のように連続する項目の場合に「A-D」と省略して記述できる\n    # 略記の展開はアルファベット1文字もしくは数字の範囲に限り、略記1つを指定したときのみ展開される\n    #   choice[A-D] -> choice[A,B,C,D] と等価\n    #   choice[b-g] -> choice[b,c,d,e,f,g] と等価\n    #   choice[3-7] -> choice[3,4,5,6,7] と等価\n    #   choice[A-D,Z] -> 展開されない。 \"A-D\", \"Z\" から選ぶ\n    #   choice[D-A] -> 展開されない。\n    class Choice\n      PREFIX_PATTERN = /choice/.freeze\n\n      module BlockDelimiter\n        BRACKET = :bracket # \"[\"\n        PAREN = :paren # \"(\"\n        SPACE = :space # /\\s/\n      end\n\n      DELIMITER = {\n        bracket: /,/,\n        paren: /,/,\n        space: /\\s+/,\n      }.freeze\n\n      DELIMITER_CHAR = {\n        bracket: \", \",\n        paren: \", \",\n        space: \" \",\n      }.freeze\n\n      TERMINATION = {\n        bracket: /\\]/,\n        paren: /\\)/,\n        space: /$/,\n      }.freeze\n\n      SUFFIX = {\n        bracket: \"]\",\n        paren: \")\",\n        space: \"\",\n      }.freeze\n\n      class << self\n        # @param command [String]\n        # @param _game_system [BCDice::Base]\n        # @param randomizer [Randomizer]\n        # @return [Result, nil]\n        def eval(command, _game_system, randomizer)\n          cmd = parse(command)\n          cmd&.roll(randomizer)\n        end\n\n        private\n\n        def parse(command)\n          scanner = StringScanner.new(command)\n          scanner.skip(/\\s+/)\n\n          secret = !scanner.scan(/S/i).nil?\n          unless scanner.scan(/choice/i)\n            return nil\n          end\n\n          takes = scanner.scan(/\\d+/)&.to_i || 1\n          if takes == 0\n            return nil\n          end\n\n          type =\n            case scanner.scan(/\\(|\\[|\\s+/)\n            when \"[\"\n              BlockDelimiter::BRACKET\n            when \"(\"\n              BlockDelimiter::PAREN\n            when String\n              BlockDelimiter::SPACE\n            else\n              return nil\n            end\n\n          delimiter = DELIMITER[type]\n          termination = TERMINATION[type]\n\n          items = []\n          while (item = scanner.scan_until(delimiter))\n            items.push(item.delete_suffix(\",\"))\n          end\n\n          last_item = scanner.scan_until(termination)\n          unless last_item\n            return nil\n          end\n\n          items.push(last_item.delete_suffix(SUFFIX[type]))\n\n          items = items.map(&:strip).reject(&:empty?)\n          if items.size == 1\n            items = parse_multi_item_shorthand(items.first)\n          end\n\n          if items.empty? || items.size < takes\n            return nil\n          end\n\n          new(\n            secret: secret,\n            block_delimiter: type,\n            takes: takes,\n            items: items\n          )\n        end\n\n        def parse_multi_item_shorthand(str)\n          parse_multi_nums_shorthand(str) || parse_multi_chars_shorthand(str) || []\n        end\n\n        def parse_multi_nums_shorthand(str)\n          m = /^(\\d+)-(\\d+)$/.match(str)\n          unless m\n            return nil\n          end\n\n          first = m[1].to_i\n          last = m[2].to_i\n          if first > last\n            return nil\n          end\n\n          return first.upto(last).to_a\n        end\n\n        def parse_multi_chars_shorthand(str)\n          m = /^([a-z])-([a-z])$/.match(str) || /^([A-Z])-([A-Z])$/.match(str)\n          unless m\n            return nil\n          end\n\n          first = m[1]\n          last = m[2]\n          if first > last\n            return nil\n          end\n\n          return first.upto(last).to_a\n        end\n      end\n\n      # @param secret [Boolean]\n      # @param block_delimiter [BlockDelimiter::BRACKET, BlockDelimiter::PAREN, BlockDelimiter::SPACE]\n      # @param takes [Integer] 何個チョイスするか\n      # @param items [Array<String>]\n      def initialize(secret:, block_delimiter:, takes:, items:)\n        @secret = secret\n        @block_delimiter = block_delimiter\n        @takes = takes\n        @items = items\n      end\n\n      # @param randomizer [Randomizer]\n      # @return [Result]\n      def roll(randomizer)\n        if @items.size > 100\n          return Result.new(\"項目数は100以下としてください\")\n        end\n\n        items = @items.dup\n        chosens = []\n        @takes.times do\n          index = randomizer.roll_index(items.size)\n          chosens << items.delete_at(index)\n        end\n\n        Result.new.tap do |r|\n          chosen = chosens.join(DELIMITER_CHAR[@block_delimiter])\n\n          r.secret = @secret\n          r.text = \"(\#{expr()}) ＞ \#{chosen}\"\n        end\n      end\n\n      def expr\n        takes = @takes == 1 ? nil : @takes\n\n        case @block_delimiter\n        when BlockDelimiter::SPACE\n          \"choice\#{takes} \#{@items.join(' ')}\"\n        when BlockDelimiter::BRACKET\n          \"choice\#{takes}[\#{@items.join(',')}]\"\n        when BlockDelimiter::PAREN\n          \"choice\#{takes}(\#{@items.join(',')})\"\n        end\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "self", "require", "<module:BCDice>", "<module:CommonCommand>", "<class:Choice>", "freeze", "<module:BlockDelimiter>", "eval", "command", "_game_system", "randomizer", "cmd", "parse", "private", "scanner", "StringScanner", "new", "skip", "secret", "scan", "nil?", "!", "takes", "$ret_or_1", "1", "0", "type", "BlockDelimiter::BRACKET", "BlockDelimiter", "BlockDelimiter::PAREN", "String", "BlockDelimiter::SPACE", "delimiter", "DELIMITER", "[]", "termination", "TERMINATION", "items", "item", "scan_until", "push", "delete_suffix", "last_item", "SUFFIX", "reject", "map", "to_proc", "size", "parse_multi_item_shorthand", "first", "empty?", "<", "str", "$ret_or_2", "parse_multi_nums_shorthand", "parse_multi_chars_shorthand", "m", "match", "to_i", "last", "2", ">", "upto", "to_a", "initialize", "$kwargs", "@secret", "@block_delimiter", "block_delimiter", "@takes", "@items", "roll", "100", "Result", "dup", "chosens", "times", "block in roll", "block (2 levels) in roll", "index", "roll_index", "<<", "delete_at", "tap", "r", "chosen", "join", "DELIMITER_CHAR", "secret=", "text=", "expr"], :mappings=>"AAAAA,+CAAAA,gBAAAA;EAAAA;;;EAEAC,IAAAC,SAAAA,CAAQF,SAARE;EAEAF,OAAAG;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;MAqCEA,OAAAC;MAAAA;;QAAAA;;AAAAA;;QACE,0CAAiB,QAAQC,QAAAA,CAAAA,CAAzB;QAE