V,YAAMzD,KAAAA,CAAAA,CAAImE,OAAAA,EAAAA,EAAAA,EAAVN,aAAmBO,CAAnBP,EAAAC;AAAAA;AAAAA;;;YAAmB;YACjBO,SAASV,OAAOW,MAAAA,CAAMC,oBAAcrD,OAAAA,CAACiC,oBAADjC,CAApBoD;YAEhBF,CAACI,YAAAA,CAAUtB,WAAVsB;YACDV,OAACW,MAAAA,CAASX,GAAD,GAAA,CAAI9E,IAAA0F,MAAAA,CAAAA,CAAJ,CAAA,GAAWZ,MAAX,GAAA,CAAiBO,MAAjB,CAARI,CAAAA,EAAAA,MAADL,CAACK,SAAAA,EAAAA,EAAAA,CAAAA,EAAAA,mBAJHZ,CAAAA,GAAAA,SAAAA,CAAUM;QAZZZ,CAAAA;QAoBAnE,OAAAsF,oBAAAA,gBAAAA;AAAAA,UAAAA;;;UACEpE,QAAQ,CAAA,MAAA+C,UAAA,EAAU7C,CAAV,CAAA,GAAA,CAAc,GAAd,IAAA,CAAoB6C,UAApB,CAAA;UAGR,IAAA,QAAKtC,IAAAH,oBAAAG,UAAL,EADAR,CAAAA,YAAK4C,oBAAL5C,CACA,CAAA;YACEmE,OAACA,QAAD,GAAA,CAASpE,KAAT,CAAA,GAAeoE,GAAf,GAAA,CAAkBpB,UAAMgB,MAAAA,CAAMI,GAANJ,CAAxB;UADF,OAEA,IAAA,QAAK3D,IAAAC,oBAAAD,YAAL,EA3NR,SA2NQ,CAAA;YACE+D,OAACA,QAAD,GAAA,CAASpE,KAAT,CAAA,GAAeoE,GAAf,GAAA,CAAkBpB,UAAMgB,MAAAA,CAAMI,GAANJ,CAAxB,CAAA,GAAmCI;UADrC,OAEA,IAAA,QAAK7D,IAAAD,oBAAAC,UAAL,EA7NR,SA6NQ,CAAA;YACE6D,OAACA,QAAD,GAAA,CAASpE,KAAT,CAAA,GAAeoE,GAAf,GAAA,CAAkBpB,UAAMgB,MAAAA,CAAMI,GAANJ,CAAxB,CAAA,GAAmCI;UADrC;YALAA,OAAA;UAKA;QARFA,CAAAA;MA3KFtF,GAAAA,WAAAA,EAAAA,IAAAA;IArCFD,GAAAA,WAAAA;EADFD,GAAAA,WAAAA;AAJAH;"}}, {:offset=>{:line=>3852, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["bcdice/common_command/d66_dice.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nmodule BCDice\n  module CommonCommand\n    class D66Dice\n      PREFIX_PATTERN = /D66/.freeze\n\n      class << self\n        # @param command [String]\n        # @param game_system [BCDice::Base]\n        # @param randomizer [Randomizer]\n        # @return [Result, nil]\n        def eval(command, game_system, randomizer)\n          cmd = parse(command, game_system)\n          cmd&.eval(randomizer)\n        end\n\n        private\n\n        def parse(command, game_system)\n          command = command.split(\" \", 2).first\n\n          m = /^(S)?D66([ANSD])?$/i.match(command.upcase)\n          return nil unless m\n\n          new(\n            secret: !m[1].nil?,\n            sort_type: sort_type_from_suffix(m[2]) || game_system.d66_sort_type,\n            suffix: m[2]\n          )\n        end\n\n        def sort_type_from_suffix(suffix)\n          case suffix\n          when \"A\", \"S\"\n            D66SortType::ASC\n          when \"D\"\n            D66SortType::DESC\n          when \"N\"\n            D66SortType::NO_SORT\n          end\n        end\n      end\n\n      # @param secret [Boolean]\n      # @param sort_type [Symbol]\n      # @param suffix [String, nil]\n      def initialize(secret:, sort_type:, suffix:)\n        @secret = secret\n        @sort_type = sort_type\n        @suffix = suffix\n      end\n\n      # @param randomizer [Randomizer]\n      # @return [Result]\n      def eval(randomizer)\n        value = roll(randomizer)\n\n        Result.new.tap do |r|\n          r.secret = @secret\n          r.text = \"(D66\#{@suffix}) ＞ \#{value}\"\n        end\n      end\n\n      private\n\n      def roll(randomizer)\n        dice_list = Array.new(2) { randomizer.roll_once(6) }\n\n        case @sort_type\n        when D66SortType::ASC\n          dice_list.sort!\n        when D66SortType::DESC\n          dice_list.sort!.reverse!\n        end\n\n        return dice_list[0] * 10 + dice_list[1]\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "<module:BCDice>", "<module:CommonCommand>", "<class:D66Dice>", "freeze", "eval", "command", "game_system", "randomizer", "cmd", "self", "parse", "private", "split", "2", "first", "m", "match", "upcase", "new", "[]", "1", "nil?", "!", "$ret_or_1", "sort_type_from_suffix", "d66_sort_type", "suffix", "D66SortType::ASC", "D66SortType", "D66SortType::DESC", "D66SortType::NO_SORT", "initialize", "$kwargs", "@secret", "secret", "@sort_type", "sort_type", "@suffix", "value", "roll", "tap", "Result", "block in eval", "r", "block (2 levels) in eval", "secret=", "text=", "dice_list", "Array", "block in roll", "block (2 levels) in roll", "roll_once", "6", "sort!", "reverse!", "+", "*", "0", "10"], :mappings=>"AAAAA,iDAAAA,gBAAAA;EAAAA;;EAEAA,OAAAC;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;MACEA,OAAAC;MAAAA;;QAAAA;;AAAAA;;QACE,0CAAiB,KAAKC,QAAAA,CAAAA,CAAtB;QAEA;UAAA;;;;AAKEC,UAAAA,oBAAAA,iBAASC,OAAD,EAAUC,WAAV,EAAuBC,UAA/BH,GAAAA,MAAAA,IAAAA,wCAAAA;AAAAA,YAAAA;;;YACEI,MAAMC,IAAAC,OAAAA,CAAML,OAAN,EAAeC,WAAfI;YACNN,OAAA,CAAA,KAAAI,GAAA,qCAAA,EAAA,MAAA,CAAUD,UAAV,CAAA,EAFFH;cAAAA;cAAAA;YAAAA;UAAAA,CAAAA;UAKAK,IAAAE,SAAAA,CAAAA;;AAEAD,UAAAA,qBAAAA,iBAAUL,OAAD,EAAUC,WAAnBI;AAAAA,YAAAA;;;YACEL,UAAUA,OAAOO,OAAAA,CAAOF,GAAd,EAAmBG,CAAZD,CAAcE,OAAAA,CAAAA;YAE/BC,IAAI,qBAAqBC,OAAAA,CAAOX,OAAOY,QAAAA,CAAAA,CAAdD;YACzB,KAAA,QAAkBD,CAAlB,CAAA;cAAA,OAAO;YAAP;YAEAL,OAAAD,IAAAS,KAAAA,CACE,2CAAA,UAASH,CAACI,OAAAA,CAACC,CAADD,CAAGE,SAAAA,CAAAA,CAALC,MAAAA,CAAAA,CAAR,EAAA,aACW,CAAA,QAAAC,CAAAA,YAAAd,IAAAe,uBAAAA,CAAsBT,CAACI,OAAAA,CAACN,CAADM,CAAvBK,CAAAD,CAAA,CAAA,GAAA,CAAA,SAAA,IAAA,CAA+BjB,WAAWmB,eAAAA,CAAAA,CAA1C,CAAA,CADX,EAAA,UAEQV,CAACI,OAAAA,CAACN,CAADM,CAFT,EADFD;UANFR,CAAAA;UAaA,OAAAc,qCAAAA,iCAA0BE,MAA1BF;AAAAA;;YAEE,QADKE,MACL;cAAA,KAAKF,GAAL;cAAA,KAAUA,GAAV;gBACEA,OAAAG,IAAAC,iBAAAD;cACF,KAAKH,GAAL;gBACEA,OAAAK,IAAAD,iBAAAC;cACF,KAAKL,GAAL;gBACEA,OAAAM,IAAAF,iBAAAE;cADF;gBALAN,OAAA;YACA;UAFFA,CAAAA;QAzBF,4BAASf,IAAT;;AAwCAsB,QAAAA,0BAAAA,sBA/CNC,OA+CMD;AAAAA,UAAAA;;;UA/CN;UA+CqB;UAAS;UAAY;UAClCE,cAAUC;UACVC,iBAAaC;UACbL,OAAAM,CAAAA,cAAUX,MAAVW;QAHFN,CAAAA;;AAQA3B,QAAAA,oBAAAA,yBAASG,UAATH;AAAAA,UAAAA;;;UACEkC,QAAQ7B,IAAA8B,MAAAA,CAAKhC,UAALgC;UAERnC,OAAUoC,MAAVC,YAAMvB,KAAAA,CAAAA,CAAIsB,OAAAA,EAAAA,EAAAA,EAAVE,aAAmBC,CAAnBD,EAAAE;AAAAA;AAAAA;;;YAAmB;YACjBD,CAACE,YAAAA,CAAUZ,WAAVY;YACDD,OAACE,MAAAA,CAASF,MAAD,GAAA,CAAOP,WAAP,CAAA,GAAeO,MAAf,GAAA,CAAqBN,KAArB,CAARQ,CAAAA,EAAAA,MAADH,CAACG,SAAAA,EAAAA,EAAAA,CAAAA,EAAAA,mBAFHJ,CAAAA,GAAAA,SAAAA,CAAUF;QAHZpC,CAAAA;QASAK,IAAAE,SAAAA,CAAAA;QAEAT,OAAAqC,oBAAAA,gBAAShC,UAATgC;AAAAA,UAAAA;;;UACEQ,YAAiB7B,MAAL8B,WAAK9B,OAAAA,EAAAA,CAAKL,CAALK,CAAAA,EAAL+B,aAAAA;YAAeC,OAAA3C,UAAU4C,WAAAA,CAAWC,CAAXD,CAAzBF,CAAK/B;UAGjB,IAAA,QAAKS,IAAAC,iBAAAD,QAAL,EADAJ,CAAAA,YAAKY,cAALZ,CACA,CAAA;YACEwB,SAASM,UAAAA,CAAAA;UADX,OAEA,IAAA,QAAKxB,IAAAD,iBAAAC,SAAL,EAxER,SAwEQ,CAAA;YACEkB,SAASM,UAAAA,CAAAA,CAAMC,aAAAA,CAAAA;UADjB;YAHA;UAGA;UAIA,OAAyBC,SAALC,UAAbT,SAAS5B,OAAAA,CAACsC,CAADtC,CAAIqC,EAAEE,EAAFF,CAAKD,EAAER,SAAS5B,OAAAA,CAACC,CAADD,CAAXoC;QAV3BhB,CAAAA;MA9DFrC,GAAAA,WAAAA,EAAAA,IAAAA;IADFD,GAAAA,WAAAA;EADFD,GAAAA,WAAAA;AAFAD;"}}, {:offset=>{:line=>3966, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["bcdice/common_command/repeat.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nrequire \"strscan\"\n\nmodule BCDice\n  module CommonCommand\n    # リピート\n    #\n    # 繰り返し回数を指定して、特定のコマンドを複数回実行する\n    # 例）\n    #   x5 choice[A,B,C,D] #=> `choice[A,B,C,D]`を5回実行する\n    #   rep2 CC<=75        #=> `CC<=75`を2回実行する\n    #   repeat10 2D6+5     #=> `2D6+6`を10回実行する\n    #\n    # このコマンドを入れ子させることは許容しない。繰り返し回数の爆発に繋がるためである。\n    # 以下は実行時にエラーとなる。\n    #   x10 repeat100 100D100\n    class Repeat\n      PREFIX_PATTERN = /(repeat|rep|x)\\d+/.freeze\n\n      REPEAT_LIMIT = 100\n\n      class << self\n        def eval(command, game_system, randomizer)\n          cmd = parse(command)\n          cmd&.roll(game_system, randomizer)\n        end\n\n        private\n\n        def parse(command)\n          scanner = StringScanner.new(command)\n\n          secret = !scanner.scan(/s/i).nil?\n          keyword = scanner.scan(/repeat|rep|x/i)\n          repeat_times = scanner.scan(/\\d+/)&.to_i\n          whitespace = scanner.scan(/\\s+/)\n          if keyword.nil? || repeat_times.nil? || whitespace.nil?\n            return nil\n          end\n\n          trailer = scanner.post_match\n          if trailer.nil? || trailer.empty?\n            return nil\n          end\n\n          new(\n            secret: secret,\n            times: repeat_times,\n            trailer: trailer\n          )\n        end\n      end\n\n      def initialize(secret:, times:, trailer:)\n        @secret = secret\n        @times = times\n        @trailer = trailer\n      end\n\n      def roll(game_system, randomizer)\n        err = validate()\n        return err if err\n\n        results = Array.new(@times) do\n          cmd = game_system.class.new(@trailer)\n          cmd.randomizer = randomizer\n          cmd.eval()\n        end\n\n        if results.count { |i| i == nil } == @times\n          return result_with_text(\"繰り返し対象のコマンドが実行できませんでした (\#{@trailer})\")\n        end\n\n        text = results.map.with_index(1) { |r, index| \"\\#\#{index}\\n\#{r.text}\" }.join(\"\\n\\n\")\n        secret = @secret || results.any?(&:secret?)\n\n        Result.new.tap do |r|\n          r.secret = secret\n          r.text = text\n        end\n      end\n\n      private\n\n      def validate\n        if /\\A(repeat|rep|x)\\d+/.match?(@trailer)\n          result_with_text(\"Repeatコマンドの重複はできません\")\n        elsif @times < 1 || REPEAT_LIMIT < @times\n          result_with_text(\"繰り返し回数は1以上、\#{REPEAT_LIMIT}以下としてください\")\n        end\n      end\n\n      def result_with_text(text)\n        Result.new.tap do |r|\n          r.secret = @secret\n          r.text = text\n        end\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "self", "require", "<module:BCDice>", "<module:CommonCommand>", "<class:Repeat>", "freeze", "100", "eval", "command", "game_system", "randomizer", "cmd", "parse", "private", "scanner", "StringScanner", "new", "secret", "scan", "nil?", "!", "keyword", "repeat_times", "whitespace", "trailer", "post_match", "empty?", "initialize", "$kwargs", "@secret", "@times", "times", "@trailer", "roll", "err", "validate", "results", "Array", "block in roll", "block (2 levels) in roll", "class", "randomizer=", "count", "i", "==", "result_with_text", "text", "with_index", "map", "1", "r", "index", "join", "$ret_or_1", "any?", "to_proc", "tap", "Result", "secret=", "text=", "match?", "<", "REPEAT_LIMIT", "block in result_with_text", "block (2 levels) in result_with_text"], :mappings=>"AAAAA,+CAAA