AAAA,EAAXT,aAA6BY,CAAD,EAAIC,KAAhCb;;YAA6B;YAAG;YAAOC,OAACA,GAAD,GAAA,CAAKY,KAAL,CAAA,GAAWZ,IAAX,GAAA,CAAeW,CAACJ,MAAAA,CAAAA,CAAhB,EAAvCR,CAAWS,CAAqDK,MAAAA,CAAMnB,MAANmB;UACvEnC,SAAS,CAAA,QAAAoC,CAAAA,YAAAxB,WAAAwB,CAAA,CAAA,GAAA,CAAA,SAAA,IAAA,CAAkBC,MAAPlB,OAAOkB,QAAAA,EAAAA,EAAAA,EAAO,SAADC,SAAAA,CAAAA,CAAND,CAAlB,CAAA;UAETrB,OAAUuB,MAAVC,YAAMzC,KAAAA,CAAAA,CAAIwC,OAAAA,EAAAA,EAAAA,EAAVlB,aAAmBY,CAAnBZ,EAAAC;;;YAAmB;YACjBW,CAACQ,YAAAA,CAAUzC,MAAVyC;YACDnB,OAACoB,MAAAA,CAAQb,IAARa,CAAAA,EAAAA,MAADT,CAACS,SAAAA,EAAAA,EAAAA,CAAAA,EAAAA,mBAFHrB,CAAUkB,EAjBZvB;YAAAA;YAAAA;UAAAA;QAAAA,CAAAA;QAuBAjC,IAAAa,SAAAA,CAAAA;;AAEAsB,QAAAA,wBAAAA,oBAAAA;AAAAA,UAAAA;;UACE,IAAA,QAAG,oBAAqByB,WAAAA,CAAQ5B,YAAR4B,CAAxB,CAAA;YACEzB,OAAAnC,IAAA6C,kBAAAA,CAAiBV,qBAAjBU;UADF,OAEA,IAAM,CAAA,QAAOgB,OAAP/B,UAAO+B,EAAEZ,CAAFY,CAAP,CAAA,IAAA,CAAA,QAA2BA,OAAbC,kBAAaD,EAAE/B,UAAF+B,CAA3B,CAAA,CAAA,CAAN;YACE1B,OAAAnC,IAAA6C,kBAAAA,CAAkBV,aAAD,GAAA,CAAc2B,kBAAd,CAAA,GAA2B3B,WAA5CU;UADF;YAxFRV,OAAA;UAwFQ;QAHFA,CAAAA;QAQA/B,OAAAyC,gCAAAA,4BAAqBC,IAArBD;AAAAA,UAAAA;;UACEA,OAAUW,MAAVC,YAAMzC,KAAAA,CAAAA,CAAIwC,OAAAA,EAAAA,EAAAA,EAAVO,aAAmBb,CAAnBa,EAAAC;AAAAA;;;YAAmB;YACjBd,CAACQ,YAAAA,CAAU7B,WAAV6B;YACDM,OAACL,MAAAA,CAAQb,IAARa,CAAAA,EAAAA,MAADT,CAACS,SAAAA,EAAAA,EAAAA,CAAAA,EAAAA,mBAFHI,CAAAA,GAAAA,SAAAA,CAAUP;QADZX,CAAAA;MA5EFzC,GAAAA,WAAAA,EAAAA,IAAAA;IAZFD,GAAAA,WAAAA;EADFD,GAAAA,WAAAA;AAJAH;"}}, {:offset=>{:line=>4102, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["bcdice/format.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nmodule BCDice\n  module Format\n    module_function\n\n    # 比較演算子を文字列表記にする\n    #\n    # @param op [Symbol]\n    # @return [String, nil]\n    def comparison_operator(op)\n      case op\n      when :==\n        \"=\"\n      when :'!='\n        \"<>\"\n      when Symbol\n        op.to_s\n      end\n    end\n\n    # 修正値を文字列表記にする\n    #\n    # @param number [Integer, nil]\n    # @return [String]\n    def modifier(number)\n      if number.nil?\n        nil\n      elsif number == 0\n        \"\"\n      elsif number > 0\n        \"+\#{number}\"\n      else\n        number.to_s\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "<module:BCDice>", "<module:Format>", "self", "module_function", "comparison_operator", "op", "$ret_or_1", "Symbol", "to_s", "modifier", "number", "nil?", "0", ">"], :mappings=>"AAAAA,gCAAAA,gBAAAA;EAAAA;;EAEAA,OAAAC;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;;MACEC,IAAAC,iBAAAA,CAAAA;;AAMAC,MAAAA,mCAAAA,+BAAwBC,EAAxBD;AAAAA,QAAAA;;QAEE,IAAA,QAAK,IAAL,EADAE,CAAAA,YAAKD,EAALC,CACA,CAAA;UACEF,OAAAA;QADF,OAEA,IAAA,QAAK,IAAL,EAdN,SAcM,CAAA;UACEA,OAAAA;QADF,OAEA,IAAA,QAAKG,YAAL,EAhBN,SAgBM,CAAA;UACEH,OAAAC,EAAEG,MAAAA,CAAAA;QADJ;UALAJ,OAAA;QAKA;MANFA,CAAAA;MAeAH,OAAAQ,wBAAAA,oBAAaC,MAAbD;AAAAA;QACE,IAAA,QAAGC,MAAMC,SAAAA,CAAAA,CAAT,CAAA;UACEF,OAAA;QADF,OAEA,IAAA,MAAMC,MAAN,EAAgBE,CAAhB,CAAA;UACEH,OAAAA;QADF,OAEA,IAAA,QAAaI,OAAPH,MAAOG,EAAED,CAAFC,CAAb,CAAA;UACEJ,OAACA,GAAD,GAAA,CAAIC,MAAJ;QADF;UAGED,OAAAC,MAAMF,MAAAA,CAAAA;QAHR;MALFC,CAAAA;IAtBFR,GAAAA,WAAAA;EADFD,GAAAA,WAAAA;AAFAD;"}}, {:offset=>{:line=>4147, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["bcdice/common_command/barabara_dice/result.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nrequire \"bcdice/result\"\n\nmodule BCDice\n  module CommonCommand\n    module BarabaraDice\n      # バラバラロールの結果を表すクラス\n      class Result < ::BCDice::Result\n        # @return [Array<Array<Integer>>] 出目のグループの配列\n        attr_accessor :last_dice_list_list\n        # @return [Array<Integer>] すべての出目が格納される配列\n        attr_accessor :last_dice_list\n        # @return [Integer] 成功数\n        attr_accessor :success_num\n\n        # @param text [String, nil] 結果の文章\n        def initialize(text = nil)\n          super(text)\n\n          @last_dice_list_list = []\n          @last_dice_list = []\n          @success_num = 0\n        end\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "self", "require", "<module:BCDice>", "<module:CommonCommand>", "<module:BarabaraDice>", "<class:Result>", "attr_accessor", "initialize", "text", "@last_dice_list_list", "@last_dice_list", "@success_num", "0", "BCDice::Result", "BCDice"], :mappings=>"AAAAA,6DAAAA,gBAAAA;EAAAA;;;EAEAC,IAAAC,SAAAA,CAAQF,eAARE;EAEAF,OAAAG;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;MACEA,OAAAC;MAAAA;;QAAAA;;QAEEA,OAAAC;QAAAA;;;;UAEEL,IAAAM,eAAAA,CAAc,qBAAdA;UAEAN,IAAAM,eAAAA,CAAc,gBAAdA;UAEAN,IAAAM,eAAAA,CAAc,aAAdA;UAGAD,OAAAE,0BAAAA,sBAAeC,IAAfD;AAAAA,YAAAA;;YAAAA;;YAAe,yBAAO;YACpB,OAAAP,IAAA,EAAA,0DAAA,cAAA,EAAA,CAAMQ,IAAN,CAAA,EAAA,IAAA;YAEAC,2BAAuB;YACvBC,sBAAkB;YAClBH,OAAAI,CAAAA,mBAAeC,CAAfD;UALFJ,CAAAA,IAAAA;QATFF,GAAAA,WAAAA,EAAeQ,IAAAC,aAAAD,WAAfR;MAFFD,GAAAA,WAAAA;IADFD,GAAAA,WAAAA;EADFD,GAAAA,WAAAA;AAJAH;"}}, {:offset=>{:line=>4192, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["bcdice/common_command/barabara_dice/node.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nrequire \"bcdice/format\"\nrequire \"bcdice/common_command/barabara_dice/result\"\n\nmodule BCDice\n  module CommonCommand\n    module BarabaraDice\n      module Node\n        class Command\n          def initialize(secret:, notations:, cmp_op:, target_number:)\n            @secret = secret\n            @notations = notations\n            @cmp_op = cmp_op\n            @target_number = target_number\n          end\n\n          # @param game_system [Base] ゲームシステム\n          # @param randomizer [Randomizer] ランダマイザ\n          # @return [Result]\n          def eval(game_system, randomizer)\n            round_type = game_system.round_type\n            notations = @notations.map { |n| n.to_dice(round_type) }\n            cmp_op = @cmp_op || game_system.default_cmp_op\n            target_number = @target_number&.eval(round_type) || game_system.default_target_number\n\n            dice_list_list = notations.map { |d| d.roll(randomizer) }\n            dice_list_list.map!(&:sort) if game_system.sort_barabara_dice?\n\n            dice_list = dice_list_list.flatten\n\n            count_of_1 = dice_list.count(1)\n            success_num = cmp_op ? dice_list.count { |d| d.send(cmp_op, target_number) } : 0\n            success_num_text = \"成功数\#{success_num}\" if cmp_op\n\n            sequence = [\n              \"(\#{notations.join('+')}\#{Format.comparison_operator(cmp_op)}\#{target_number})\",\n              dice_list.join(\",\"),\n              success_num_text,\n              game_system.grich_text(count_of_1, dice_list.size, success_num)\n            ].compact\n\n            Result.new.tap do |r|\n              r.secret = @secret\n              r.text = sequence.join(\" ＞ \")\n              r.last_dice_list_list = dice_list_list\n              r.last_dice_list = dice_list\n              r.success_num = success_num\n            end\n          end\n        end\n\n        class Notation\n          # @param times [#eval]\n          # @param sides [#eval]\n          def initialize(times, sides)\n            @times = times\n            @sides = sides\n          end\n\n          # @param round_type [Symbol]\n          def to_dice(round_type)\n            times = @times.eval(round_type)\n            sides = @sides.eval(round_type)\n\n            Dice.new(times, sides)\n          end\n        end\n\n        class Dice\n          # @param times [Integer]\n          # @param sides [Integer]\n          def initialize(times, sides)\n            @times = times\n            @sides = sides\n          end\n\n          # @param randomizer [BCDice::Randomizer]\n          # @return [Array<Integer>]\n          def roll(randomizer)\n            randomizer.roll_barabara(@times, @sides)\n          end\n\n          # @return [String]\n          def to_s\n            \"\#{@times}B\#{@sides}\"\n          end\n        end\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "self", "require", "<module:BCDice>", "<module:CommonCommand>", "<module:BarabaraDice>", "<module:Node>", "<class:Command>", "initializ