A,0BAAAA,sBAAejD,GAAD,EAAMC,OAAN,EAAeC,MAA7B+C;AAAAA;YACUA,OAAAC,IAAApB,IAAAC,gBAAAD,SAAAoB,WAAwB3H,KAAAA,CAAKyE,GAAGK,OAAAA,CAAClB,CAADkB,CAAR9E;UADlC0H,CAAAA;UAKA7H,OAAA+H,4BAAAA,wBAAiBnD,GAAD,EAAMC,OAAN,EAAeC,MAA/BiD;AAAAA;YACEA,OAAAnD,GAAGK,OAAAA,CAAClB,CAADkB;UADL8C,CAAAA;QA/YM/H,GAAAA,WAAAA,EAAegI,IAAAC,UAAAD,WAAfhI;MADFD,GAAAA,WAAAA;IADFD,GAAAA,WAAAA;EADFD,GAAAA,WAAAA;AAbAH;"}}, {:offset=>{:line=>4604, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["bcdice/common_command/reroll_dice.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nrequire \"bcdice/normalize\"\nrequire \"bcdice/format\"\nrequire \"bcdice/common_command/reroll_dice/parser\"\n\nmodule BCDice\n  module CommonCommand\n    # 個数振り足しダイス\n    #\n    # ダイスを振り、条件を満たした出目の個数だけダイスを振り足す。振り足しがなくなるまでこれを繰り返す。\n    # 成功条件を満たす出目の個数を調べ、成功数を表示する。\n    #\n    # 例\n    #   2R6+1R10[>3]>=5\n    #   2R6+1R10>=5@>3\n    #\n    # 振り足し条件は角カッコかコマンド末尾の @ で指定する。\n    # [>3] の場合、3より大きい出目が出たら振り足す。\n    # [3] のように数値のみ指定されている場合、成功条件の比較演算子を流用する。\n    # 上記の例の時、出目が\n    #   \"2R6\"  -> [5,6] [5,4] [1,3]\n    #   \"1R10\" -> [9] [1]\n    # だとすると、 >=5 に該当するダイスは5つなので成功数5となる。\n    #\n    # 成功条件が書かれていない場合、成功数0として扱う。\n    # 振り足し条件が数値のみ指定されている場合、比較演算子は >= が指定されたとして振舞う。\n    module RerollDice\n      PREFIX_PATTERN = /\\d+R\\d+/.freeze\n      REROLL_LIMIT = 10000\n\n      class << self\n        def eval(command, game_system, randomizer)\n          cmd = Parser.parse(command)\n          cmd&.eval(game_system, randomizer)\n        end\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "self", "require", "<module:BCDice>", "<module:CommonCommand>", "<module:RerollDice>", "freeze", "10000", "eval", "command", "game_system", "randomizer", "cmd", "Parser", "parse"], :mappings=>"AAAAA,oDAAAA,gBAAAA;EAAAA;;;EAEAC,IAAAC,SAAAA,CAAQF,kBAARE;EACAD,IAAAC,SAAAA,CAAQF,eAARE;EACAD,IAAAC,SAAAA,CAAQF,0CAARE;EAEAF,OAAAG;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;MAoBEA,OAAAC;MAAAA;;QAAAA;;;QACE,0CAAiB,SAASC,QAAAA,CAAAA,CAA1B;QACA,wCAAeC,KAAf;QAEAF,OAAA;UAAA;;UACE,OAAAG,oBAAAA,iBAASC,OAAD,EAAUC,WAAV,EAAuBC,UAA/BH,GAAAA,MAAAA,IAAAA,wCAAAA;AAAAA,YAAAA;;;YACEI,MAAMC,YAAMC,OAAAA,CAAOL,OAAPK;YACZN,OAAA,CAAA,KAAAI,GAAA,qCAAA,EAAA,MAAA,CAAUF,WAAV,EAAuBC,UAAvB,CAAA,EAFFH;cAAAA;cAAAA;YAAAA;UAAAA,CAAAA;QADF,4BAASP,IAAT;MAJFI,GAAAA,WAAAA;IApBFD,GAAAA,WAAAA;EADFD,GAAAA,WAAAA;AANAH;"}}, {:offset=>{:line=>4648, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["bcdice/common_command/upper_dice/node.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nmodule BCDice\n  module CommonCommand\n    module UpperDice\n      module Node\n        class Command\n          # @param secret [Boolean]\n          # @param notations [Array<Notation>]\n          # @param modifier [Integer]\n          # @param cmp_op [Symbol, nil]\n          # @param target_number [Integer, nil]\n          # @param reroll_threshold [Integer]\n          def initialize(secret:, notations:, modifier:, cmp_op:, target_number:, reroll_threshold: nil)\n            @secret = secret\n            @notations = notations\n            @modifier = modifier\n            @cmp_op = cmp_op\n            @target_number = target_number\n            @reroll_threshold = reroll_threshold\n          end\n\n          # 上方無限ロールを実行する\n          #\n          # @param randomizer [Randomizer]\n          # @return [Result, nil]\n          def eval(game_system, randomizer)\n            round_type = game_system.round_type\n\n            dice_list = @notations.map { |n| n.to_dice(round_type) }\n            reroll_threshold = @reroll_threshold&.eval(round_type) || game_system.upper_dice_reroll_threshold || 0\n            modifier = @modifier&.eval(round_type) || 0\n            target_number = @target_number&.eval(round_type)\n\n            expr = expr(dice_list, reroll_threshold, modifier, target_number)\n\n            if reroll_threshold <= 1\n              return result_with_text(\"(\#{expr}) ＞ 無限ロールの条件がまちがっています\")\n            end\n\n            roll_list = dice_list.map do |n|\n              n.roll(randomizer, reroll_threshold, game_system.sort_barabara_dice?)\n            end.reduce([], :concat)\n\n            result =\n              if @cmp_op\n                result_success_count(roll_list, modifier, target_number)\n              else\n                result_max_sum(roll_list, modifier)\n              end\n\n            sequence = [\n              \"(\#{expr})\",\n              interlim_expr(roll_list, modifier),\n              result\n            ]\n\n            result_with_text(sequence.join(\" ＞ \"))\n          end\n\n          private\n\n          def result_success_count(roll_list, modifier, target_number)\n            success_count = roll_list.count do |e|\n              x = e[:sum] + modifier\n              x.send(@cmp_op, target_number)\n            end\n\n            \"成功数\#{success_count}\"\n          end\n\n          def result_max_sum(roll_list, modifier)\n            sum_list = roll_list.map { |e| e[:sum] }\n            total = sum_list.sum() + modifier\n            max = sum_list.map { |i| i + modifier }.max\n\n            \"\#{max}/\#{total}(最大/合計)\"\n          end\n\n          # ダイスロールの結果を文字列に変換する\n          # 振り足しがなければその数値、振り足しがあれば合計と各ダイスの出目を出力する\n          #\n          # @param roll_list [Array<Hash>]\n          # @param modifier [Integer]\n          # @return [String]\n          def interlim_expr(roll_list, modifier)\n            dice = roll_list.map do |e|\n              if e[:list].size == 1\n                e[:sum]\n              else\n                \"\#{e[:sum]}[\#{e[:list].join(',')}]\"\n              end\n            end.join(\",\")\n\n            dice + Format.modifier(modifier)\n          end\n\n          # パース済みのコマンドを文字列で表示する\n          #\n          # @return [String]\n          def expr(dice_list, reroll_threshold, modifier, target_number)\n            formated_cmp_op = Format.comparison_operator(@cmp_op)\n            formated_modifier = Format.modifier(modifier)\n\n            \"\#{dice_list.join('+')}[\#{reroll_threshold}]\#{formated_modifier}\#{formated_cmp_op}\#{target_number}\"\n          end\n\n          def result_with_text(text)\n            Result.new.tap do |r|\n              r.secret = @secret\n              r.text = text\n            end\n          end\n        end\n\n        class Notation\n          # @param roll_times [Object]\n          # @param sides [Object]\n          def initialize(roll_times, sides)\n            @roll_times = roll_times\n            @sides = sides\n          end\n\n          # @param round_type [Symbol]\n          # @return [Dice]\n          def to_dice(round_type)\n            roll_times = @roll_times.eval(round_type)\n            sides = @sides.eval(round_type)\n\n            Dice.new(roll_times, sides)\n          end\n        end\n\n        class Dice\n          # @param roll_times [Integer]\n          # @param sides [Integer]\n          def initialize(roll_times, sides)\n            @roll_times = roll_times\n            @sides = sides\n          end\n\n          # @param randomizer [BCDice::Randomizer]\n          # @param reroll_threshold [Integer]\n          # @param sort [Boolean]\n          # @return [Array<Hash>]\n          def roll(randomizer, reroll_threshold, sort)\n            ret = Array.new(@roll_times) do\n              list = roll_ones(randomizer, reroll_threshold)\n              {sum: list.sum(), list: list}\n            end\n\n            if sort\n              ret = ret.sort_by { |e| e[:sum] }\n            end\n\n            return ret\n          end\n\n          # @return [String]\n          def to_s\n            \"\#{@roll_times}U\#{@sides}\"\n          end\n\n          private\n\n          def roll_ones(randomizer, reroll_threshold)\n            dice_list = []\n\n            loop do\n              value = randomizer.roll_once(@sides)\n              dice_list.push(value)\n              break if value < reroll_threshold\n            end\n\n            return dice_list\n          end\n        end\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "<module:BCDice>", "<module:CommonCommand>", "<module:UpperDice>", "<module:Node>", "<class:Command>", "initialize", "$kwargs", "@secret", "secret", "@notations", "notations", "@modifier", "modifier", "@cmp_op", "cmp_op", "@target_number", "target_number", "@reroll_threshold", "reroll_threshold", "eval", "game_system", "randomizer", "round_type", "dice_list", "map", "block in eval", "n", "block (2 levels) in eval", "to_dice", "$ret_or_1", "$ret_or_2", "upper_dice_reroll_threshold", "0", "expr", "self", "<=", "1", "result_with_text", "roll_list", "roll", "sort_barabara_dice?", "reduce", "result", "result_success_count", "result_max_sum", "sequence", "interlim_expr", "join", "private", "success_count", "count", "block in result_success_count", "e", "block (2 levels) in result_success_count", "x", "+", "[]", "send", "sum_list", "block in result_max_sum", "block (2 levels) in result_max_sum", "total", "sum", "max", "i", "dice", "block in interlim_expr", "size", "block (2 levels) in interlim_expr", "Format", "formated_cmp_op", "comparison_operator", "formated_modifier", "text", "tap", "Result", "new", "block in result_with_text", "r", "block (2 levels) in result_with_text", "secret=", "text=", "<class:Notation>", "roll_times", "sides", "@roll_times", "@sides", "Dice", "<class:Dice>", "sort", "ret", "Array", "block in roll", "block (2 levels) in roll", "list", "roll_ones", "sort_by", "to_s", "loop", "block in roll_ones", "block (2 levels) in roll_ones", "value", "roll_once", "push", "<"], :mappings=>"AAAAA,wDAAAA,gBAAAA;EAAAA;;EAEAA,OAAAC;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;MACEA,OAAAC;MAAAA;;QAAAA;;QACEA,OAAAC;QAAAA;;UAAAA;;;UACEC;UAAAA;;YAAAA;;AAAAA;;;AAOEC,YAAAA,0BAAAA,sBAbVC,OAaUD;AAAAA,cAAAA;;;cAbV;cAayB;cAAS;cAAY;cAAW;cAAS;;cAAgB,sDAAA,iDAAkB;cACxFE,cAAUC;cACVC,iBAAaC;cACbC,gBAAYC;cACZC,cAAUC;cACVC,qBAAiBC;cACjBX,OAAAY,CAAAA,wBAAoBC,gBAApBD;YANFZ,CAAAA;;AAaAc,YAAAA,oBAAAA,yBAASC,W