rozen_string_literal: true\n\nrequire \"bcdice/common_command/upper_dice/parser\"\n\nmodule BCDice\n  module CommonCommand\n    # 上方無限ロール\n    #\n    # ダイスを1つ振る、その出目が閾値より大きければダイスを振り足すのを閾値未満の出目が出るまで繰り返す。\n    # これを指定したダイス数だけおこない、それぞれのダイスの合計値を求める。\n    # それらと目標値を比較し、成功した数を表示する。\n    #\n    # フォーマットは以下の通り\n    # 2U4+1U6[4]>=6\n    # 2U4+1U6>=6@4\n    #\n    # 閾値は角カッコで指定するか、コマンドの末尾に @6 のように指定する。\n    # 閾値の指定が重複した場合、角カッコが優先される。\n    # この時、出目が\n    #   \"2U4\" -> 3[3], 10[4,4,2]\n    #   \"1U6\" -> 6[4,2]\n    # だとすると、 >=6 に該当するダイスは2つなので成功数2となる。\n    #\n    # 2U4[4]+10>=6 のように修正値を指定できる。修正値は全てのダイスに補正を加え、以下のようになる。\n    #   \"2U4\" -> 3[3]+10=13, 10[4,4,2]+10=20\n    #\n    # 比較演算子が書かれていない場合、ダイスの最大値と全ダイスの合計値が出力される。\n    # 全ダイスの合計値には補正値が1回だけ適用される\n    # 2U4[4]+10\n    #   \"2U4\" -> 3[3]+10=13, 10[4,4,2]+10=20\n    #   最大値：20\n    #   合計値：23 = 3[3]+10[4,4,2]+10\n    module UpperDice\n      PREFIX_PATTERN = /\\d+U\\d+/.freeze\n\n      class << self\n        # @param command [String]\n        # @param game_system [BCDice::Base]\n        # @param randomizer [BCDice::Randomizer]\n        # @return [UpperDice, nil]\n        def eval(command, game_system, randomizer)\n          cmd = Parser.parse(command)\n          cmd&.eval(game_system, randomizer)\n        end\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "self", "require", "<module:BCDice>", "<module:CommonCommand>", "<module:UpperDice>", "freeze", "eval", "command", "game_system", "randomizer", "cmd", "Parser", "parse"], :mappings=>"AAAAA,mDAAAA,gBAAAA;EAAAA;;;EAEAC,IAAAC,SAAAA,CAAQF,yCAARE;EAEAF,OAAAG;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;MA2BEA,OAAAC;MAAAA;;QAAAA;;;QACE,0CAAiB,SAASC,QAAAA,CAAAA,CAA1B;QAEAD,OAAA;UAAA;;UAKE,OAAAE,oBAAAA,iBAASC,OAAD,EAAUC,WAAV,EAAuBC,UAA/BH,GAAAA,MAAAA,IAAAA,wCAAAA;AAAAA,YAAAA;;;YACEI,MAAMC,YAAMC,OAAAA,CAAOL,OAAPK;YACZN,OAAA,CAAA,KAAAI,GAAA,qCAAA,EAAA,MAAA,CAAUF,WAAV,EAAuBC,UAAvB,CAAA,EAFFH;cAAAA;cAAAA;YAAAA;UAAAA,CAAAA;QALF,4BAASN,IAAT;MAHFI,GAAAA,WAAAA;IA3BFD,GAAAA,WAAAA;EADFD,GAAAA,WAAAA;AAJAH;"}}, {:offset=>{:line=>5187, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["bcdice/common_command/version.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nmodule BCDice\n  module CommonCommand\n    module Version\n      PREFIX_PATTERN = /BCDiceVersion/.freeze\n\n      class << self\n        def eval(command, _game_system, _randomizer)\n          command = command.split(\" \", 2).first\n          if command.match?(/^BCDiceVersion$/i)\n            Result.new.tap do |r|\n              r.text = \"BCDice \#{BCDice::VERSION}\"\n            end\n          end\n        end\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "<module:BCDice>", "<module:CommonCommand>", "<module:Version>", "freeze", "eval", "command", "_game_system", "_randomizer", "split", "2", "first", "match?", "tap", "Result", "new", "block in eval", "r", "block (2 levels) in eval", "text=", "BCDice::VERSION", "BCDice", "self"], :mappings=>"AAAAA,gDAAAA,gBAAAA;EAAAA;;EAEAA,OAAAC;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;MACEA,OAAAC;MAAAA;;QAAAA;;;QACE,0CAAiB,eAAeC,QAAAA,CAAAA,CAAhC;QAEAD,OAAA;UAAA;;UACE,OAAAE,oBAAAA,iBAASC,OAAD,EAAUC,YAAV,EAAwBC,WAAhCH;AAAAA;;YACEC,UAAUA,OAAOG,OAAAA,CAAOJ,GAAd,EAAmBK,CAAZD,CAAcE,OAAAA,CAAAA;YAC/B,IAAA,QAAGL,OAAOM,WAAAA,CAAQ,kBAARA,CAAV,CAAA;cACEP,OAAUQ,MAAVC,YAAMC,KAAAA,CAAAA,CAAIF,OAAAA,EAAAA,EAAAA,EAAVG,aAAmBC,CAAnBD,EAAAE;;;gBAAmB;gBACjBA,OAACC,MAAAA,CAASD,SAAD,GAAA,CAAUE,IAAAC,YAAAD,YAAV,CAARD,CAAAA,EAAAA,MAADF,CAACE,SAAAA,EAAAA,EAAAA,CAAAA,EAAAA,mBADHH,CAAUH;YADZ;cAVVR,OAAA;YAUU;UAFFA,CAAAA;QADF,4BAASiB,IAAT;MAHFnB,GAAAA,WAAAA;IADFD,GAAAA,WAAAA;EADFD,GAAAA,WAAAA;AAFAD;"}}, {:offset=>{:line=>5230, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["bcdice/common_command.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nrequire \"bcdice/common_command/add_dice\"\nrequire \"bcdice/common_command/barabara_dice\"\nrequire \"bcdice/common_command/tally_dice\"\nrequire \"bcdice/common_command/calc\"\nrequire \"bcdice/common_command/choice\"\nrequire \"bcdice/common_command/d66_dice\"\nrequire \"bcdice/common_command/repeat\"\nrequire \"bcdice/common_command/reroll_dice\"\nrequire \"bcdice/common_command/upper_dice\"\nrequire \"bcdice/common_command/version\"\n\nmodule BCDice\n  module CommonCommand\n    COMMANDS = [\n      AddDice,\n      BarabaraDice,\n      TallyDice,\n      Calc,\n      Choice,\n      D66Dice,\n      Repeat,\n      RerollDice,\n      UpperDice,\n      Version,\n    ].freeze\n  end\nend\n"], :names=>["<main>", "self", "require", "<module:BCDice>", "<module:CommonCommand>", "AddDice", "BarabaraDice", "TallyDice", "Calc", "Choice", "D66Dice", "Repeat", "RerollDice", "UpperDice", "Version", "freeze"], :mappings=>"AAAAA,2BAAAA;EAAAA;;;EAEAC,IAAAC,SAAAA,CAAQF,gCAARE;EACAD,IAAAC,SAAAA,CAAQF,qCAARE;EACAD,IAAAC,SAAAA,CAAQF,kCAARE;EACAD,IAAAC,SAAAA,CAAQF,4BAARE;EACAD,IAAAC,SAAAA,CAAQF,8BAARE;EACAD,IAAAC,SAAAA,CAAQF,gCAARE;EACAD,IAAAC,SAAAA,CAAQF,8BAARE;EACAD,IAAAC,SAAAA,CAAQF,mCAARE;EACAD,IAAAC,SAAAA,CAAQF,kCAARE;EACAD,IAAAC,SAAAA,CAAQF,+BAARE;EAEAF,OAAAG;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;MACEA,OAAA,oCAAW,CACTC,aADS,EAETC,kBAFS,EAGTC,eAHS,EAITC,UAJS,EAKTC,YALS,EAMTC,aANS,EAOTC,YAPS,EAQTC,gBARS,EASTC,eATS,EAUTC,aAVS,CAWVC,QAAAA,CAAAA,CAXD;IADFX,GAAAA,WAAAA;EADFD,GAAAA,WAAAA;AAbAH;"}}]}